// Generated from ecma262/spec.html — do not edit by hand.
const sections = {"1":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">Script :\n  ScriptBody?\n\nScriptBody :\n  StatementList[~Yield, ~Await, ~Return]</pre>\n\n    ","2":"<h2>Syntax</h2>\n    <pre class=\"emu-grammar\">Module :\n  ModuleBody?\n\nModuleBody :\n  ModuleItemList\n\nModuleItemList :\n  ModuleItem\n  ModuleItemList ModuleItem\n\nModuleItem :\n  ImportDeclaration\n  ExportDeclaration\n  StatementListItem[~Yield, +Await, ~Return]\n\nModuleExportName :\n  IdentifierName\n  StringLiteral</pre>\n\n    ","":"","1.1":"<pre class=\"emu-grammar\">Script : ScriptBody</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if the LexicallyDeclaredNames of <emu-nt>ScriptBody</emu-nt> contains any duplicate entries.\n        </li>\n        <li>\n          It is a Syntax Error if any element of the LexicallyDeclaredNames of <emu-nt>ScriptBody</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>ScriptBody</emu-nt>.\n        </li>\n      </ul>\n      <pre class=\"emu-grammar\">ScriptBody : StatementList</pre>\n      <ul>\n        <li>\n          It is a Syntax Error if <emu-nt>StatementList</emu-nt> Contains <code>super</code> unless the source text containing <code>super</code> is eval code that is being processed by a direct eval. Additional early error rules for <code>super</code> within direct eval are defined in 19.2.1.1.\n        </li>\n        <li>\n          It is a Syntax Error if <emu-nt>StatementList</emu-nt> Contains <emu-nt>NewTarget</emu-nt> unless the source text containing <emu-nt>NewTarget</emu-nt> is eval code that is being processed by a direct eval. Additional early error rules for <emu-nt>NewTarget</emu-nt> in direct eval are defined in 19.2.1.1.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsDuplicateLabels of <emu-nt>StatementList</emu-nt> with argument « » is <b>true</b>.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsUndefinedBreakTarget of <emu-nt>StatementList</emu-nt> with argument « » is <b>true</b>.\n        </li>\n        <li>\n          It is a Syntax Error if ContainsUndefinedContinueTarget of <emu-nt>StatementList</emu-nt> with arguments « » and « » is <b>true</b>.\n        </li>\n        <li>\n          It is a Syntax Error if AllPrivateIdentifiersValid of <emu-nt>StatementList</emu-nt> with argument « » is <b>false</b> unless the source text containing <emu-nt>ScriptBody</emu-nt> is eval code that is being processed by a direct eval.\n        </li>\n      </ul>\n    ","1.2":"<dl class=\"header\">\n      </dl>\n      <pre class=\"emu-grammar\">Script : ScriptBody?</pre>\n      <emu-alg><ol><li>If <emu-nt>ScriptBody</emu-nt> is present and the Directive Prologue of <emu-nt>ScriptBody</emu-nt> contains a Use Strict Directive, return <b>true</b>.</li><li>Return <b>false</b>.</li></ol></emu-alg>\n    ","1.3":"<pre class=\"emu-grammar\">Script : [empty]</pre>\n      <emu-alg><ol><li>Return <b>undefined</b>.</li></ol></emu-alg>\n    ","1.4":"<p>A <dfn id=\"script-record\" variants=\"Script Records\">Script Record</dfn> encapsulates information about a script being evaluated. Each script record contains the fields listed in table-script-records.</p>\n\n      <emu-table id=\"table-script-records\" caption=\"Script Record Fields\">\n        <table>\n          <thead>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n          </thead>\n          <tr>\n            <td>\n              [[Realm]]\n            </td>\n            <td>\n              a Realm Record\n            </td>\n            <td>\n              The realm within which this script was created.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[ECMAScriptCode]]\n            </td>\n            <td>\n              a <emu-nt>Script</emu-nt> Parse Node\n            </td>\n            <td>\n              The result of parsing the source text of this script.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[LoadedModules]]\n            </td>\n            <td>\n              a List of LoadedModuleRequest Records\n            </td>\n            <td>\n              A map from the specifier strings imported by this script to the resolved Module Record. The list does not contain two different Records <var>r1</var> and <var>r2</var> such that ModuleRequestsEqual(<var>r1</var>, <var>r2</var>) is <b>true</b>.\n            </td>\n          </tr>\n          <tr>\n            <td>\n              [[HostDefined]]\n            </td>\n            <td>\n              anything (default value is <emu-const>empty</emu-const>)\n            </td>\n            <td>\n              Field reserved for use by host environments that need to associate additional information with a script.\n            </td>\n          </tr>\n        </table>\n      </emu-table>\n    ","1.5":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd>It creates a Script Record based upon the result of parsing <var>sourceText</var> as a <emu-nt>Script</emu-nt>.</dd>\n      </dl>\n\n      <emu-alg><ol><li>Let <var>script</var> be ParseText(<var>sourceText</var>, <emu-nt>Script</emu-nt>).</li><li>If <var>script</var> is a List of errors, return <var>script</var>.</li><li>Return Script Record { [[Realm]]: <var>realm</var>, [[ECMAScriptCode]]: <var>script</var>, [[LoadedModules]]: « », [[HostDefined]]: <var>hostDefined</var> }.</li></ol></emu-alg>\n      <emu-note>\n        <p>An implementation may parse script source text and analyse it for Early Error conditions prior to evaluation of ParseScript for that script source text. However, the reporting of any errors must be deferred until the point where this specification actually performs ParseScript upon that source text.</p>\n      </emu-note>\n    ","1.6":"<dl class=\"header\">\n      </dl>\n\n      <emu-alg><ol><li>Let <var>globalEnv</var> be <var>scriptRecord</var>.[[Realm]].[[GlobalEnv]].</li><li>Let <var>scriptContext</var> be a new ECMAScript code execution context.</li><li>Set the Function of <var>scriptContext</var> to <b>null</b>.</li><li>Set the Realm of <var>scriptContext</var> to <var>scriptRecord</var>.[[Realm]].</li><li>Set the ScriptOrModule of <var>scriptContext</var> to <var>scriptRecord</var>.</li><li>Set the VariableEnvironment of <var>scriptContext</var> to <var>globalEnv</var>.</li><li>Set the LexicalEnvironment of <var>scriptContext</var> to <var>globalEnv</var>.</li><li>Set the PrivateEnvironment of <var>scriptContext</var> to <b>null</b>.</li><li>Suspend the running execution context.</li><li>Push <var>scriptContext</var> onto the execution context stack; <var>scriptContext</var> is now the running execution context.</li><li>Let <var>script</var> be <var>scriptRecord</var>.[[ECMAScriptCode]].</li><li>Let <var>result</var> be Completion(GlobalDeclarationInstantiation(<var>script</var>, <var>globalEnv</var>)).</li><li>If <var>result</var> is a normal completion, then<ol><li>Set <var>result</var> to Completion(Evaluation of <var>script</var>).</li><li>If <var>result</var> is a normal completion and <var>result</var>.[[Value]] is <emu-const>empty</emu-const>, then<ol><li>Set <var>result</var> to NormalCompletion(<b>undefined</b>).</li></ol></li></ol></li><li>Suspend <var>scriptContext</var> and remove it from the execution context stack.</li><li>Assert: The execution context stack is not empty.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>Return ? <var>result</var>.</li></ol></emu-alg>\n    ","1.7":"<dl class=\"header\">\n        <dt>description</dt>\n        <dd><var>script</var> is the <emu-nt>Script</emu-nt> for which the execution context is being established. <var>env</var> is the global environment in which bindings are to be created.</dd>\n      </dl>\n      <emu-note>\n        <p>When an execution context is established for evaluating scripts, declarations are instantiated in the current global environment. Each global binding declared in the code is instantiated.</p>\n      </emu-note>\n      <p>It performs the following steps when called:</p>\n      <emu-alg><ol><li>Let <var>lexNames</var> be the LexicallyDeclaredNames of <var>script</var>.</li><li>Let <var>varNames</var> be the VarDeclaredNames of <var>script</var>.</li><li>For each element <var>name</var> of <var>lexNames</var>, do<ol><li>If HasLexicalDeclaration(<var>env</var>, <var>name</var>) is <b>true</b>, throw a <b>SyntaxError</b> exception.</li><li>Let <var>hasRestrictedGlobal</var> be ? HasRestrictedGlobalProperty(<var>env</var>, <var>name</var>).</li><li>NOTE: Global <code>var</code> and <code>function</code> bindings (except those that are introduced by non-strict direct eval) are non-configurable and are therefore restricted global properties.</li><li>If <var>hasRestrictedGlobal</var> is <b>true</b>, throw a <b>SyntaxError</b> exception.</li></ol></li><li>For each element <var>name</var> of <var>varNames</var>, do<ol><li>If HasLexicalDeclaration(<var>env</var>, <var>name</var>) is <b>true</b>, throw a <b>SyntaxError</b> exception.</li></ol></li><li>Let <var>varDeclarations</var> be the VarScopedDeclarations of <var>script</var>.</li><li>Let <var>functionsToInitialize</var> be a new empty List.</li><li>Let <var>declaredFunctionNames</var> be a new empty List.</li><li>For each element <var>varDecl</var> of <var>varDeclarations</var>, in reverse List order, do<ol><li>If <var>varDecl</var> is not either a <emu-nt>VariableDeclaration</emu-nt>, a <emu-nt>ForBinding</emu-nt>, or a <emu-nt>BindingIdentifier</emu-nt>, then<ol><li>Assert: <var>varDecl</var> is either a <emu-nt>FunctionDeclaration</emu-nt>, a <emu-nt>GeneratorDeclaration</emu-nt>, an <emu-nt>AsyncFunctionDeclaration</emu-nt>, or an <emu-nt>AsyncGeneratorDeclaration</emu-nt>.</li><li>NOTE: If there are multiple function declarations for the same name, the last declaration is used.</li><li>Let <var>fn</var> be the sole element of the BoundNames of <var>varDecl</var>.</li><li>If <var>declaredFunctionNames</var> does not contain <var>fn</var>, then<ol><li>Let <var>fnDefinable</var> be ? CanDeclareGlobalFunction(<var>env</var>, <var>fn</var>).</li><li>If <var>fnDefinable</var> is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>Append <var>fn</var> to <var>declaredFunctionNames</var>.</li><li>Insert <var>varDecl</var> as the first element of <var>functionsToInitialize</var>.</li></ol></li></ol></li></ol></li><li>Let <var>declaredVarNames</var> be a new empty List.</li><li>For each element <var>varDecl</var> of <var>varDeclarations</var>, do<ol><li>If <var>varDecl</var> is either a <emu-nt>VariableDeclaration</emu-nt>, a <emu-nt>ForBinding</emu-nt>, or a <emu-nt>BindingIdentifier</emu-nt>, then<ol><li>For each String <var>vn</var> of the BoundNames of <var>varDecl</var>, do<ol><li>If <var>declaredFunctionNames</var> does not contain <var>vn</var>, then<ol><li>Let <var>vnDefinable</var> be ? CanDeclareGlobalVar(<var>env</var>, <var>vn</var>).</li><li>If <var>vnDefinable</var> is <b>false</b>, throw a <b>TypeError</b> exception.</li><li>If <var>declaredVarNames</var> does not contain <var>vn</var>, then<ol><li>Append <var>vn</var> to <var>declaredVarNames</var>.</li></ol></li></ol></li></ol></li></ol></li></ol></li><li>NOTE: No abnormal terminations occur after this algorithm step if the global object is an ordinary object. However, if the global object is a Proxy exotic object it may exhibit behaviours that cause abnormal terminations in some of the following steps.</li><li>If the host is a web browser or otherwise supports B.3.2, then<ol><li>Let <var>strict</var> be ScriptIsStrict of <var>script</var>.</li><li>If <var>strict</var> is <b>false</b>, then<ol><li>Let <var>declaredFunctionOrVarNames</var> be the list-concatenation of <var>declaredFunctionNames</var> and <var>declaredVarNames</var>.</li><li>For each <emu-nt>FunctionDeclaration</emu-nt> <var>f</var> that is directly contained in the <emu-nt>StatementList</emu-nt> of any <emu-nt>Block</emu-nt>, <emu-nt>CaseClause</emu-nt>, or <emu-nt>DefaultClause</emu-nt> <var>x</var> such that <var>script</var> Contains <var>x</var> is <b>true</b>, do<ol><li>Let <var>funcName</var> be the StringValue of the <emu-nt>BindingIdentifier</emu-nt> of <var>f</var>.</li><li>If replacing the <emu-nt>FunctionDeclaration</emu-nt> <var>f</var> with a <emu-nt>VariableStatement</emu-nt> that has <var>funcName</var> as a <emu-nt>BindingIdentifier</emu-nt> would not produce any Early Errors for <var>script</var>, then<ol><li>If HasLexicalDeclaration(<var>env</var>, <var>funcName</var>) is <b>false</b>, then<ol><li>Let <var>fnDefinable</var> be ? CanDeclareGlobalVar(<var>env</var>, <var>funcName</var>).</li><li>If <var>fnDefinable</var> is <b>true</b>, then<ol><li>NOTE: A var binding for <var>funcName</var> is only instantiated here if it is neither a VarDeclaredName nor the name of another <emu-nt>FunctionDeclaration</emu-nt>.</li><li>If <var>declaredFunctionOrVarNames</var> does not contain <var>funcName</var>, then<ol><li>Perform ? CreateGlobalVarBinding(<var>env</var>, <var>funcName</var>, <b>false</b>).</li><li>Append <var>funcName</var> to <var>declaredFunctionOrVarNames</var>.</li></ol></li><li>When the <emu-nt>FunctionDeclaration</emu-nt> <var>f</var> is evaluated, perform the following steps in place of the <emu-nt>FunctionDeclaration</emu-nt> Evaluation algorithm provided in 15.2.6:<ol><li>Let <var>gEnv</var> be the running execution context's VariableEnvironment.</li><li>Let <var>bEnv</var> be the running execution context's LexicalEnvironment.</li><li>Let <var>fObj</var> be ! <var>bEnv</var>.GetBindingValue(<var>funcName</var>, <b>false</b>).</li><li>Perform ? <emu-meta effects=\"user-code\"><var>gEnv</var>.SetMutableBinding(<var>funcName</var>, <var>fObj</var>, <b>false</b>)</emu-meta>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></li></ol></li></ol></li></ol></li></ol></li></ol></li></ol></li><li>Let <var>lexDeclarations</var> be the LexicallyScopedDeclarations of <var>script</var>.</li><li>Let <var>privateEnv</var> be <b>null</b>.</li><li>For each element <var>lexDecl</var> of <var>lexDeclarations</var>, do<ol><li>NOTE: Lexically declared names are only instantiated here but not initialized.</li><li>For each element <var>dn</var> of the BoundNames of <var>lexDecl</var>, do<ol><li>If IsConstantDeclaration of <var>lexDecl</var> is <b>true</b>, then<ol><li>Perform ? <emu-meta effects=\"user-code\"><var>env</var>.CreateImmutableBinding(<var>dn</var>, <b>true</b>)</emu-meta>.</li></ol></li><li>Else,<ol><li>Perform ? <emu-meta effects=\"user-code\"><var>env</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>)</emu-meta>.</li></ol></li></ol></li></ol></li><li>For each Parse Node <var>f</var> of <var>functionsToInitialize</var>, do<ol><li>Let <var>fn</var> be the sole element of the BoundNames of <var>f</var>.</li><li>Let <var>fo</var> be InstantiateFunctionObject of <var>f</var> with arguments <var>env</var> and <var>privateEnv</var>.</li><li>Perform ? <emu-meta effects=\"user-code\">CreateGlobalFunctionBinding(<var>env</var>, <var>fn</var>, <var>fo</var>, <b>false</b>)</emu-meta>.</li></ol></li><li>For each String <var>vn</var> of <var>declaredVarNames</var>, do<ol><li>Perform ? <emu-meta effects=\"user-code\">CreateGlobalVarBinding(<var>env</var>, <var>vn</var>, <b>false</b>)</emu-meta>.</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      <emu-note>\n        <p>Early errors specified in 16.1.1 prevent name conflicts between function/var declarations and let/const/class declarations as well as redeclaration of let/const/class bindings for declaration contained within a single <emu-nt>Script</emu-nt>. However, such conflicts and redeclarations that span more than one <emu-nt>Script</emu-nt> are detected as runtime errors during GlobalDeclarationInstantiation. If any such errors are detected, no bindings are instantiated for the script. However, if the global object is defined using Proxy exotic objects then the runtime tests for conflicting declarations may be unreliable resulting in an abrupt completion and some global declarations not being instantiated. If this occurs, the code for the <emu-nt>Script</emu-nt> is not evaluated.</p>\n        <p>Unlike explicit var or function declarations, properties that are directly created on the global object result in global bindings that may be shadowed by let/const/class declarations.</p>\n      </emu-note>\n    ","2.1":"","2.1.1":"<pre class=\"emu-grammar\">ModuleBody : ModuleItemList</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the LexicallyDeclaredNames of <emu-nt>ModuleItemList</emu-nt> contains any duplicate entries.\n          </li>\n          <li>\n            It is a Syntax Error if any element of the LexicallyDeclaredNames of <emu-nt>ModuleItemList</emu-nt> also occurs in the VarDeclaredNames of <emu-nt>ModuleItemList</emu-nt>.\n          </li>\n          <li>\n            It is a Syntax Error if the ExportedNames of <emu-nt>ModuleItemList</emu-nt> contains any duplicate entries.\n          </li>\n          <li>\n            It is a Syntax Error if any element of the ExportedBindings of <emu-nt>ModuleItemList</emu-nt> does not also occur in either the VarDeclaredNames of <emu-nt>ModuleItemList</emu-nt>, or the LexicallyDeclaredNames of <emu-nt>ModuleItemList</emu-nt>.\n          </li>\n          <li>\n            It is a Syntax Error if <emu-nt>ModuleItemList</emu-nt> Contains <code>super</code>.\n          </li>\n          <li>\n            It is a Syntax Error if <emu-nt>ModuleItemList</emu-nt> Contains <emu-nt>NewTarget</emu-nt>.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsDuplicateLabels of <emu-nt>ModuleItemList</emu-nt> with argument « » is <b>true</b>.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsUndefinedBreakTarget of <emu-nt>ModuleItemList</emu-nt> with argument « » is <b>true</b>.\n          </li>\n          <li>\n            It is a Syntax Error if ContainsUndefinedContinueTarget of <emu-nt>ModuleItemList</emu-nt> with arguments « » and « » is <b>true</b>.\n          </li>\n          <li>\n            It is a Syntax Error if AllPrivateIdentifiersValid of <emu-nt>ModuleItemList</emu-nt> with argument « » is <b>false</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>The duplicate ExportedNames rule implies that multiple <code>export default</code> <emu-nt>ExportDeclaration</emu-nt> items within a <emu-nt>ModuleBody</emu-nt> is a Syntax Error. Additional error conditions relating to conflicting or duplicate declarations are checked during module linking prior to evaluation of a <emu-nt>Module</emu-nt>. If any such errors are detected the <emu-nt>Module</emu-nt> is not evaluated.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleExportName : StringLiteral</pre>\n        <ul>\n          <li>It is a Syntax Error if IsStringWellFormedUnicode(SV of <emu-nt>StringLiteral</emu-nt>) is <b>false</b>.</li>\n        </ul>\n      ","2.1.2":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It creates a List of all of the local name bindings defined by <var>importEntries</var>.</dd>\n        </dl>\n        <emu-alg><ol><li>Let <var>localNames</var> be a new empty List.</li><li>For each ImportEntry Record <var>i</var> of <var>importEntries</var>, do<ol><li>Append <var>i</var>.[[LocalName]] to <var>localNames</var>.</li></ol></li><li>Return <var>localNames</var>.</li></ol></emu-alg>\n      ","2.1.3":"<p>A <dfn id=\"modulerequest-record\" variants=\"ModuleRequest Records\">ModuleRequest Record</dfn> represents the request to import a module with given import attributes. It consists of the following fields:</p>\n        <emu-table id=\"table-modulerequest-fields\" caption=\"ModuleRequest Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Specifier]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The module specifier\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Attributes]]\n              </td>\n              <td>\n                a List of ImportAttribute Records\n              </td>\n              <td>\n                The import attributes\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>A <dfn id=\"loadedmodulerequest-record\" variants=\"LoadedModuleRequest Records\">LoadedModuleRequest Record</dfn> represents the request to import a module together with the resulting Module Record. It consists of the same fields defined in table table-modulerequest-fields, with the addition of [[Module]]:</p>\n        <emu-table id=\"table-loadedmodulerequest-fields\" caption=\"LoadedModuleRequest Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Specifier]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The module specifier\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Attributes]]\n              </td>\n              <td>\n                a List of ImportAttribute Records\n              </td>\n              <td>\n                The import attributes\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Module]]\n              </td>\n              <td>\n                a Module Record\n              </td>\n              <td>\n                The loaded module corresponding to this module request\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>An <dfn id=\"importattribute-record\" variants=\"ImportAttribute Records\">ImportAttribute Record</dfn> consists of the following fields:</p>\n        <emu-table id=\"table-importattribute-fields\" caption=\"ImportAttribute Record Fields\">\n          <table>\n            <tr>\n              <th>\n                Field Name\n              </th>\n              <th>\n                Value Type\n              </th>\n              <th>\n                Meaning\n              </th>\n            </tr>\n            <tr>\n              <td>\n                [[Key]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The attribute key\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Value]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The attribute value\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.3.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd></dd>\n          </dl>\n\n          <emu-alg><ol><li>If <var>left</var>.[[Specifier]] is not <var>right</var>.[[Specifier]], return <b>false</b>.</li><li>Let <var>leftAttrs</var> be <var>left</var>.[[Attributes]].</li><li>Let <var>rightAttrs</var> be <var>right</var>.[[Attributes]].</li><li>Let <var>leftAttrsCount</var> be the number of elements in <var>leftAttrs</var>.</li><li>Let <var>rightAttrsCount</var> be the number of elements in <var>rightAttrs</var>.</li><li>If <var>leftAttrsCount</var> ≠ <var>rightAttrsCount</var>, return <b>false</b>.</li><li>For each ImportAttribute Record <var>l</var> of <var>leftAttrs</var>, do<ol><li>If <var>rightAttrs</var> does not contain an ImportAttribute Record <var>r</var> such that <var>l</var>.[[Key]] is <var>r</var>.[[Key]] and <var>l</var>.[[Value]] is <var>r</var>.[[Value]], return <b>false</b>.</li></ol></li><li>Return <b>true</b>.</li></ol></emu-alg>\n        ","2.1.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItem</pre>\n        <emu-alg><ol><li>Return the ModuleRequests of <emu-nt>ModuleItem</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>requests</var> be the ModuleRequests of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>additionalRequests</var> be the ModuleRequests of <emu-nt>ModuleItem</emu-nt>.</li><li>For each ModuleRequest Record <var>mr</var> of <var>additionalRequests</var>, do<ol><li>If <var>requests</var> does not contain a ModuleRequest Record <var>mr2</var> such that ModuleRequestsEqual(<var>mr</var>, <var>mr2</var>) is <b>true</b>, then<ol><li>Append <var>mr</var> to <var>requests</var>.</li></ol></li></ol></li><li>Return <var>requests</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem : StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>FromClause</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause WithClause `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>FromClause</emu-nt>.</li><li>Let <var>attributes</var> be WithClauseToAttributes of <emu-nt>WithClause</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: <var>attributes</var> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>ModuleSpecifier</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier WithClause `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>ModuleSpecifier</emu-nt>.</li><li>Let <var>attributes</var> be WithClauseToAttributes of <emu-nt>WithClause</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: <var>attributes</var> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>FromClause</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: « » }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause `;`</pre>\n        <emu-alg><ol><li>Let <var>specifier</var> be the SV of <emu-nt>FromClause</emu-nt>.</li><li>Let <var>attributes</var> be WithClauseToAttributes of <emu-nt>WithClause</emu-nt>.</li><li>Return a List whose sole element is the ModuleRequest Record { [[Specifier]]: <var>specifier</var>, [[Attributes]]: <var>attributes</var> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` NamedExports `;`\n  `export` VariableStatement\n  `export` Declaration\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n      ","2.1.5":"<p>A <dfn variants=\"Module Records\">Module Record</dfn> encapsulates structural information about the imports and exports of a single module. This information is used to link the imports and exports of sets of connected modules. A Module Record includes four fields that are only used when evaluating a module.</p>\n        <p>For specification purposes Module Record values are values of the Record specification type and can be thought of as existing in a simple object-oriented hierarchy where Module Record is an abstract class with both abstract and concrete subclasses. This specification defines the abstract subclass named Cyclic Module Record and its concrete subclass named Source Text Module Record. Other specifications and implementations may define additional Module Record subclasses corresponding to alternative module definition facilities that they defined.</p>\n        <p>Module Record defines the fields listed in table-module-record-fields. All Module Definition subclasses include at least those fields. Module Record also defines the abstract method list in table-abstract-methods-of-module-records. All Module definition subclasses must provide concrete implementations of these abstract methods.</p>\n        <emu-table id=\"table-module-record-fields\" caption=\"Module Record Fields\" oldids=\"table-36\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[Realm]]\n              </td>\n              <td>\n                a Realm Record\n              </td>\n              <td>\n                The Realm within which this module was created.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Environment]]\n              </td>\n              <td>\n                a Module Environment Record or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                The Environment Record containing the top level bindings for this module. This field is set when the module is linked.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Namespace]]\n              </td>\n              <td>\n                an Object or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                The Module Namespace Object (28.3) if one has been created for this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HostDefined]]\n              </td>\n              <td>\n                anything (default value is <b>undefined</b>)\n              </td>\n              <td>\n                Field reserved for use by host environments that need to associate additional information with a module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-table id=\"table-abstract-methods-of-module-records\" type=\"abstract methods\" of=\"Module Records\" oldids=\"table-37\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Method\n                </th>\n                <th>\n                  Purpose\n                </th>\n                <th>\n                  Definitions\n                </th>\n              </tr>\n            </thead>\n            <tr id=\"abstract-loadrequestedmodules\">\n              <td>\n                LoadRequestedModules (\n                  optional <var>hostDefined</var>: anything,\n                ): a Promise\n              </td>\n              <td>\n                <p>It prepares the module for linking by recursively loading all its dependencies.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"LoadRequestedModules\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-getexportednames\">\n              <td>\n                GetExportedNames (\n                  optional <var>exportStarSet</var>: a List of Source Text Module Records,\n                ): a List of Strings\n              </td>\n              <td>\n                <p>It returns a list of all names that are either directly or indirectly exported from this module.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"GetExportedNames\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-resolveexport\">\n              <td>\n                ResolveExport (\n                  <var>exportName</var>: a String,\n                  optional <var>resolveSet</var>: a List of Records with fields [[Module]] (a Module Record) and [[ExportName]] (a String),\n                ): a ResolvedBinding Record, <b>null</b>, or <emu-const>ambiguous</emu-const>\n              </td>\n              <td>\n                <p>It returns the binding of a name exported by this module. Bindings are represented by a <dfn id=\"resolvedbinding-record\" variants=\"ResolvedBinding Records\">ResolvedBinding Record</dfn>, of the form { [[Module]]: Module Record, [[BindingName]]: String | <emu-const>namespace</emu-const> }. If the export is a Module Namespace Object without a direct binding in any module, [[BindingName]] will be set to <emu-const>namespace</emu-const>. It returns <b>null</b> if the name cannot be resolved, or <emu-const>ambiguous</emu-const> if multiple bindings were found.</p>\n                <p>Each time this operation is called with a specific <var>exportName</var>, <var>resolveSet</var> pair as arguments it must return the same result.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"ResolveExport\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-link\">\n              <td>Link ( ): either a normal completion containing <emu-const>unused</emu-const> or a throw completion</td>\n              <td>\n                <p>It prepares the module for evaluation by transitively resolving all module dependencies and creating a Module Environment Record.</p>\n                <p>LoadRequestedModules must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"Link\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-evaluate\">\n              <td>Evaluate ( ): a Promise</td>\n              <td>\n                <p>It returns a promise for the evaluation of this module and its dependencies, resolving on successful evaluation or if it has already been evaluated successfully, and rejecting for an evaluation error or if it has already been evaluated unsuccessfully. If the promise is rejected, hosts are expected to handle the promise rejection and rethrow the evaluation error. Unless this module is a Cyclic Module Record, the returned promise must be already settled.</p>\n                <p>Link must have completed successfully prior to invoking this method.</p>\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"Evaluate\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.5.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It synchronously evaluates <var>module</var>, provided that the caller guarantees that <var>module</var>'s evaluation will return an already settled promise.</dd>\n          </dl>\n\n          <emu-alg><ol><li>Assert: <var>module</var> is not a Cyclic Module Record.</li><li>Let <var>promise</var> be <var>module</var>.Evaluate().</li><li>Assert: <var>promise</var>.[[PromiseState]] is either <emu-const>fulfilled</emu-const> or <emu-const>rejected</emu-const>.</li><li>If <var>promise</var>.[[PromiseState]] is <emu-const>rejected</emu-const>, then<ol><li>If <var>promise</var>.[[PromiseIsHandled]] is <b>false</b>, perform HostPromiseRejectionTracker(<var>promise</var>, <b>\"handle\"</b>).</li><li>Set <var>promise</var>.[[PromiseIsHandled]] to <b>true</b>.</li><li>Throw <var>promise</var>.[[PromiseResult]].</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        ","2.1.6":"<p>A <dfn id=\"cyclic-module-record\" variants=\"Cyclic Module Records\">Cyclic Module Record</dfn> is used to represent information about a module that can participate in dependency cycles with other modules that are subclasses of the Cyclic Module Record type. Module Records that are not subclasses of the Cyclic Module Record type must not participate in dependency cycles with Source Text Module Records.</p>\n        <p>In addition to the fields defined in table-module-record-fields Cyclic Module Records have the additional fields listed in table-cyclic-module-fields</p>\n        <emu-table id=\"table-cyclic-module-fields\" caption=\"Additional Fields of Cyclic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[Status]]\n              </td>\n              <td>\n                <emu-const>new</emu-const>, <emu-const>unlinked</emu-const>, <emu-const>linking</emu-const>, <emu-const>linked</emu-const>, <emu-const>evaluating</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>\n              </td>\n              <td>\n                Initially <emu-const>new</emu-const>. Transitions to <emu-const>unlinked</emu-const>, <emu-const>linking</emu-const>, <emu-const>linked</emu-const>, <emu-const>evaluating</emu-const>, possibly <emu-const>evaluating-async</emu-const>, <emu-const>evaluated</emu-const> (in that order) as the module progresses throughout its lifecycle. <emu-const>evaluating-async</emu-const> indicates this module is queued to execute on completion of its asynchronous dependencies or it is a module whose [[HasTLA]] field is <b>true</b> that has been executed and is pending top-level completion.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[EvaluationError]]\n              </td>\n              <td>\n                a throw completion or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                A throw completion representing the exception that occurred during evaluation. <emu-const>empty</emu-const> if no exception occurred or if [[Status]] is not <emu-const>evaluated</emu-const>.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[DFSAncestorIndex]]\n              </td>\n              <td>\n                an integer or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                Auxiliary field used during Link and Evaluate only. If [[Status]] is either <emu-const>linking</emu-const> or <emu-const>evaluating</emu-const>, this is either the module's depth-first traversal index or that of an \"earlier\" module in the same strongly connected component.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[RequestedModules]]\n              </td>\n              <td>\n                a List of ModuleRequest Records\n              </td>\n              <td>\n                A List of the ModuleRequest Records associated with the imports in this module. The List is in source text occurrence order of the imports.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LoadedModules]]\n              </td>\n              <td>\n                a List of LoadedModuleRequest Records\n              </td>\n              <td>\n                A map from the specifier strings used by the module represented by this record to request the importation of a module with the relative import attributes to the resolved Module Record. The list does not contain two different Records <var>r1</var> and <var>r2</var> such that ModuleRequestsEqual(<var>r1</var>, <var>r2</var>) is <b>true</b>.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[CycleRoot]]\n              </td>\n              <td>\n                a Cyclic Module Record or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                The first visited module of the cycle, the root DFS ancestor of the strongly connected component. For a module not in a cycle, this would be the module itself. Once Evaluate has completed, a module's [[DFSAncestorIndex]] is the depth-first traversal index of its [[CycleRoot]].\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HasTLA]]\n              </td>\n              <td>\n                a Boolean\n              </td>\n              <td>\n                Whether this module is individually asynchronous (for example, if it's a Source Text Module Record containing a top-level await). Having an asynchronous dependency does not mean this field is <b>true</b>. This field must not change after the module is parsed.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[AsyncEvaluationOrder]]\n              </td>\n              <td>\n                <emu-const>unset</emu-const>, an integer, or <emu-const>done</emu-const>\n              </td>\n              <td>\n                This field is initially set to <emu-const>unset</emu-const>, and remains <emu-const>unset</emu-const> for fully synchronous modules. For modules that are either themselves asynchronous or have an asynchronous dependency, it is set to an integer that determines the order in which execution of pending modules is queued by 16.2.1.6.1.3.4. Once the pending module is successfully executed, the field is set to <emu-const>done</emu-const>.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[TopLevelCapability]]\n              </td>\n              <td>\n                a PromiseCapability Record or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                If this module is the [[CycleRoot]] of some cycle, and Evaluate() was called on some module in that cycle, this field contains the PromiseCapability Record for that entire evaluation. It is used to settle the Promise object that is returned from the Evaluate() abstract method. This field will be <emu-const>empty</emu-const> for any dependencies of that module, unless a top-level Evaluate() has been initiated for some of those dependencies.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[AsyncParentModules]]\n              </td>\n              <td>\n                a List of Cyclic Module Records\n              </td>\n              <td>\n                If this module or a dependency has [[HasTLA]] <b>true</b>, and execution is in progress, this tracks the parent importers of this module for the top-level execution job. These parent modules will not start executing before this module has successfully completed execution.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[PendingAsyncDependencies]]\n              </td>\n              <td>\n                an integer or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                If this module has any asynchronous dependencies, this tracks the number of asynchronous dependency modules remaining to execute for this module. A module with asynchronous dependencies will be executed when this field reaches 0 and there are no execution errors.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <p>In addition to the methods defined in table-abstract-methods-of-module-records Cyclic Module Records have the additional methods listed in table-cyclic-module-methods:</p>\n        <emu-table id=\"table-cyclic-module-methods\" type=\"abstract methods\" of=\"Cyclic Module Records\" caption=\"Additional Abstract Methods of Cyclic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Method\n                </th>\n                <th>\n                  Purpose\n                </th>\n                <th>\n                  Definitions\n                </th>\n              </tr>\n            </thead>\n            <tr id=\"abstract-initializeenvironment\">\n              <td>InitializeEnvironment ( ): either a normal completion containing <emu-const>unused</emu-const> or a throw completion</td>\n              <td>\n                It initializes the Environment Record of the module, including resolving all imported bindings, and creates the module's execution context.\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"InitializeEnvironment\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n            <tr id=\"abstract-executemodule\">\n              <td>\n                ExecuteModule (\n                  optional <var>capability</var>: a PromiseCapability Record,\n                ): either a normal completion containing <emu-const>unused</emu-const> or a throw completion\n              </td>\n              <td>\n                It evaluates the module's code within its execution context. If this module has <b>true</b> in [[HasTLA]], then a PromiseCapability Record is passed as an argument, and the method is expected to resolve or reject the given capability. In this case, the method must not throw an exception, but instead reject the PromiseCapability Record if necessary.\n              </td>\n              <td>\n                Within this specification it has definitions in the following types; hosts may provide additional types with their own definitions:\n                <emu-concrete-method-dfns for=\"ExecuteModule\"></emu-concrete-method-dfns>\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        <p>A <dfn id=\"graphloadingstate-record\" variants=\"GraphLoadingState Records\">GraphLoadingState Record</dfn> is a Record that contains information about the loading process of a module graph. It's used to continue loading after a call to HostLoadImportedModule. Each GraphLoadingState Record has the fields defined in table-graphloadingstate-record-fields:</p>\n        <emu-table id=\"table-graphloadingstate-record-fields\" caption=\"GraphLoadingState Record Fields\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[PromiseCapability]]\n              </td>\n              <td>\n                a PromiseCapability Record\n              </td>\n              <td>\n                The promise to resolve when the loading process finishes.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[IsLoading]]\n              </td>\n              <td>\n                a Boolean\n              </td>\n              <td>\n                It is true if the loading process has not finished yet, neither successfully nor with an error.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[PendingModulesCount]]\n              </td>\n              <td>\n                a non-negative integer\n              </td>\n              <td>\n                It tracks the number of pending HostLoadImportedModule calls.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Visited]]\n              </td>\n              <td>\n                a List of Cyclic Module Records\n              </td>\n              <td>\n                It is a list of the Cyclic Module Records that have been already loaded by the current loading process, to avoid infinite loops with circular dependencies.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[HostDefined]]\n              </td>\n              <td>\n                anything (default value is <emu-const>empty</emu-const>)\n              </td>\n              <td>\n                It contains host-defined data to pass from the LoadRequestedModules caller to HostLoadImportedModule.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.6.1":"<p>The following are the concrete methods for Cyclic Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.6.1.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record <var>module</var></dd>\n\n              <dt>description</dt>\n              <dd>It populates the [[LoadedModules]] of all the Module Records in the dependency graph of <var>module</var> (most of the work is done by the auxiliary function InnerModuleLoading). It takes an optional <var>hostDefined</var> parameter that is passed to the HostLoadImportedModule hook.</dd>\n            </dl>\n\n            <emu-alg><ol><li>If <var>hostDefined</var> is not present, set <var>hostDefined</var> to <emu-const>empty</emu-const>.</li><li>Let <var>pc</var> be ! NewPromiseCapability(<code class=\"emu-intrinsic\">%Promise%</code>).</li><li>Let <var>state</var> be the GraphLoadingState Record { [[IsLoading]]: <b>true</b>, [[PendingModulesCount]]: 1, [[Visited]]: « », [[PromiseCapability]]: <var>pc</var>, [[HostDefined]]: <var>hostDefined</var> }.</li><li>Perform InnerModuleLoading(<var>state</var>, <var>module</var>).</li><li>Return <var>pc</var>.[[Promise]].</li></ol></emu-alg>\n\n            <emu-note>\n              The <var>hostDefined</var> parameter can be used to pass additional information necessary to fetch the imported modules. It is used, for example, by HTML to set the correct fetch destination for <code>&lt;link rel=\"preload\" as=\"...\"&gt;</code> tags.\n              <code>import()</code> expressions never set the <var>hostDefined</var> parameter.\n            </emu-note>\n\n            ","2.1.6.1.1.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by LoadRequestedModules to recursively perform the actual loading process for <var>module</var>'s dependency graph.</dd>\n              </dl>\n\n              <emu-alg><ol><li>Assert: <var>state</var>.[[IsLoading]] is <b>true</b>.</li><li>If <var>module</var> is a Cyclic Module Record, <var>module</var>.[[Status]] is <emu-const>new</emu-const>, and <var>state</var>.[[Visited]] does not contain <var>module</var>, then<ol><li>Append <var>module</var> to <var>state</var>.[[Visited]].</li><li>Let <var>requestedModulesCount</var> be the number of elements in <var>module</var>.[[RequestedModules]].</li><li>Set <var>state</var>.[[PendingModulesCount]] to <var>state</var>.[[PendingModulesCount]] + <var>requestedModulesCount</var>.</li><li>For each ModuleRequest Record <var>request</var> of <var>module</var>.[[RequestedModules]], do<ol><li>If AllImportAttributesSupported(<var>request</var>.[[Attributes]]) is <b>false</b>, then<ol><li>Let <var>error</var> be ThrowCompletion(a newly created <b>SyntaxError</b> object).</li><li>Perform ContinueModuleLoading(<var>state</var>, <var>error</var>).</li></ol></li><li>Else if <var>module</var>.[[LoadedModules]] contains a LoadedModuleRequest Record <var>record</var> such that ModuleRequestsEqual(<var>record</var>, <var>request</var>) is <b>true</b>, then<ol><li>Perform InnerModuleLoading(<var>state</var>, <var>record</var>.[[Module]]).</li></ol></li><li>Else,<ol><li>Perform HostLoadImportedModule(<var>module</var>, <var>request</var>, <var>state</var>.[[HostDefined]], <var>state</var>).</li><li>NOTE: HostLoadImportedModule will call FinishLoadingImportedModule, which re-enters the graph loading process through ContinueModuleLoading.</li></ol></li><li>If <var>state</var>.[[IsLoading]] is <b>false</b>, return <emu-const>unused</emu-const>.</li></ol></li></ol></li><li>Assert: <var>state</var>.[[PendingModulesCount]] ≥ 1.</li><li>Set <var>state</var>.[[PendingModulesCount]] to <var>state</var>.[[PendingModulesCount]] - 1.</li><li>If <var>state</var>.[[PendingModulesCount]] = 0, then<ol><li>Set <var>state</var>.[[IsLoading]] to <b>false</b>.</li><li>For each Cyclic Module Record <var>loaded</var> of <var>state</var>.[[Visited]], do<ol><li>If <var>loaded</var>.[[Status]] is <emu-const>new</emu-const>, set <var>loaded</var>.[[Status]] to <emu-const>unlinked</emu-const>.</li></ol></li><li>Perform ! Call(<var>state</var>.[[PromiseCapability]].[[Resolve]], <b>undefined</b>, « <b>undefined</b> »).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n            ","2.1.6.1.1.2":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used to re-enter the loading process after a call to HostLoadImportedModule.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If <var>state</var>.[[IsLoading]] is <b>false</b>, return <emu-const>unused</emu-const>.</li><li>If <var>moduleCompletion</var> is a normal completion, then<ol><li>Perform InnerModuleLoading(<var>state</var>, <var>moduleCompletion</var>.[[Value]]).</li></ol></li><li>Else,<ol><li>Set <var>state</var>.[[IsLoading]] to <b>false</b>.</li><li>Perform ! Call(<var>state</var>.[[PromiseCapability]].[[Reject]], <b>undefined</b>, « <var>moduleCompletion</var>.[[Value]] »).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n            ","2.1.6.1.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record <var>module</var></dd>\n\n              <dt>description</dt>\n              <dd>On success, Link transitions this module's [[Status]] from <emu-const>unlinked</emu-const> to <emu-const>linked</emu-const>. On failure, an exception is thrown and this module's [[Status]] remains <emu-const>unlinked</emu-const>. (Most of the work is done by the auxiliary function InnerModuleLinking.)</dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: <var>module</var>.[[Status]] is one of <emu-const>unlinked</emu-const>, <emu-const>linked</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>.</li><li>Let <var>stack</var> be a new empty List.</li><li>Let <var>result</var> be Completion(InnerModuleLinking(<var>module</var>, <var>stack</var>, 0)).</li><li>If <var>result</var> is an abrupt completion, then<ol><li>For each Cyclic Module Record <var>m</var> of <var>stack</var>, do<ol><li>Assert: <var>m</var>.[[Status]] is <emu-const>linking</emu-const>.</li><li>Set <var>m</var>.[[Status]] to <emu-const>unlinked</emu-const>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is <emu-const>unlinked</emu-const>.</li><li>Return ? <var>result</var>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is one of <emu-const>linked</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>.</li><li>Assert: <var>stack</var> is empty.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n\n            ","2.1.6.1.2.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by Link to perform the actual linking process for <var>module</var>, as well as recursively on all other modules in the dependency graph. The <var>stack</var> and <var>index</var> parameters, as well as a module's [[DFSAncestorIndex]] field, keep track of the depth-first search (DFS) traversal. In particular, [[DFSAncestorIndex]] is used to discover strongly connected components (SCCs), such that all modules in an SCC transition to <emu-const>linked</emu-const> together.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If <var>module</var> is not a Cyclic Module Record, then<ol><li>Perform ? <var>module</var>.Link().</li><li>Return <var>index</var>.</li></ol></li><li>If <var>module</var>.[[Status]] is one of <emu-const>linking</emu-const>, <emu-const>linked</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>, then<ol><li>Return <var>index</var>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is <emu-const>unlinked</emu-const>.</li><li>Set <var>module</var>.[[Status]] to <emu-const>linking</emu-const>.</li><li>Let <var>moduleIndex</var> be <var>index</var>.</li><li>Set <var>module</var>.[[DFSAncestorIndex]] to <var>index</var>.</li><li>Set <var>index</var> to <var>index</var> + 1.</li><li>Append <var>module</var> to <var>stack</var>.</li><li>For each ModuleRequest Record <var>request</var> of <var>module</var>.[[RequestedModules]], do<ol><li>Let <var>requiredModule</var> be GetImportedModule(<var>module</var>, <var>request</var>).</li><li>Set <var>index</var> to ? InnerModuleLinking(<var>requiredModule</var>, <var>stack</var>, <var>index</var>).</li><li>If <var>requiredModule</var> is a Cyclic Module Record, then<ol><li>Assert: <var>requiredModule</var>.[[Status]] is one of <emu-const>linking</emu-const>, <emu-const>linked</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>.</li><li>Assert: <var>requiredModule</var>.[[Status]] is <emu-const>linking</emu-const> if and only if <var>stack</var> contains <var>requiredModule</var>.</li><li>If <var>requiredModule</var>.[[Status]] is <emu-const>linking</emu-const>, then<ol><li>Set <var>module</var>.[[DFSAncestorIndex]] to min(<var>module</var>.[[DFSAncestorIndex]], <var>requiredModule</var>.[[DFSAncestorIndex]]).</li></ol></li></ol></li></ol></li><li>Perform ? <var>module</var>.InitializeEnvironment().</li><li>Assert: <var>module</var> occurs exactly once in <var>stack</var>.</li><li>Assert: <var>module</var>.[[DFSAncestorIndex]] ≤ <var>moduleIndex</var>.</li><li>If <var>module</var>.[[DFSAncestorIndex]] = <var>moduleIndex</var>, then<ol><li>Let <var>done</var> be <b>false</b>.</li><li>Repeat, while <var>done</var> is <b>false</b>,<ol><li>Let <var>requiredModule</var> be the last element of <var>stack</var>.</li><li>Remove the last element of <var>stack</var>.</li><li>Assert: <var>requiredModule</var> is a Cyclic Module Record.</li><li>Set <var>requiredModule</var>.[[Status]] to <emu-const>linked</emu-const>.</li><li>If <var>requiredModule</var> and <var>module</var> are the same Module Record, set <var>done</var> to <b>true</b>.</li></ol></li></ol></li><li>Return <var>index</var>.</li></ol></emu-alg>\n            ","2.1.6.1.3":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Cyclic Module Record <var>module</var></dd>\n\n              <dt>description</dt>\n              <dd>Evaluate transitions this module's [[Status]] from <emu-const>linked</emu-const> to either <emu-const>evaluating-async</emu-const> or <emu-const>evaluated</emu-const>. The first time it is called on a module in a given strongly connected component, Evaluate creates and returns a Promise which resolves when the module has finished evaluating. This Promise is stored in the [[TopLevelCapability]] field of the [[CycleRoot]] for the component. Future invocations of Evaluate on any module in the component return the same Promise. (Most of the work is done by the auxiliary function InnerModuleEvaluation.)</dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: This call to Evaluate is not happening at the same time as another call to Evaluate within the surrounding agent.</li><li>Assert: <var>module</var>.[[Status]] is one of <emu-const>linked</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>.</li><li>If <var>module</var>.[[Status]] is either <emu-const>evaluating-async</emu-const> or <emu-const>evaluated</emu-const>, then<ol><li>If <var>module</var>.[[CycleRoot]] is not <emu-const>empty</emu-const>, then<ol><li>Set <var>module</var> to <var>module</var>.[[CycleRoot]].</li></ol></li><li>Else,<ol><li>Assert: <var>module</var>.[[Status]] is <emu-const>evaluated</emu-const> and <var>module</var>.[[EvaluationError]] is a throw completion.</li></ol></li></ol></li><li>If <var>module</var>.[[TopLevelCapability]] is not <emu-const>empty</emu-const>, then<ol><li>Return <var>module</var>.[[TopLevelCapability]].[[Promise]].</li></ol></li><li>Let <var>stack</var> be a new empty List.</li><li>Let <var>capability</var> be ! NewPromiseCapability(<code class=\"emu-intrinsic\">%Promise%</code>).</li><li>Set <var>module</var>.[[TopLevelCapability]] to <var>capability</var>.</li><li>Let <var>result</var> be Completion(InnerModuleEvaluation(<var>module</var>, <var>stack</var>, 0)).</li><li>If <var>result</var> is an abrupt completion, then<ol><li>For each Cyclic Module Record <var>m</var> of <var>stack</var>, do<ol><li>Assert: <var>m</var>.[[Status]] is <emu-const>evaluating</emu-const>.</li><li>Set <var>m</var>.[[Status]] to <emu-const>evaluated</emu-const>.</li><li>Set <var>m</var>.[[EvaluationError]] to <var>result</var>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is <emu-const>evaluated</emu-const>.</li><li>Assert: <var>module</var>.[[EvaluationError]] and <var>result</var> are the same Completion Record.</li><li>Perform ! Call(<var>capability</var>.[[Reject]], <b>undefined</b>, « <var>result</var>.[[Value]] »).</li></ol></li><li>Else,<ol><li>Assert: <var>module</var>.[[Status]] is either <emu-const>evaluating-async</emu-const> or <emu-const>evaluated</emu-const>.</li><li>Assert: <var>module</var>.[[EvaluationError]] is <emu-const>empty</emu-const>.</li><li>If <var>module</var>.[[Status]] is <emu-const>evaluated</emu-const>, then<ol><li>Assert: <var>module</var>.[[AsyncEvaluationOrder]] is either <emu-const>unset</emu-const> or <emu-const>done</emu-const>.</li><li>NOTE: <var>module</var>.[[AsyncEvaluationOrder]] is <emu-const>done</emu-const> if and only if <var>module</var> had already been evaluated and that evaluation was asynchronous.</li><li>Perform ! Call(<var>capability</var>.[[Resolve]], <b>undefined</b>, « <b>undefined</b> »).</li></ol></li><li>Assert: <var>stack</var> is empty.</li></ol></li><li>Return <var>capability</var>.[[Promise]].</li></ol></emu-alg>\n\n            ","2.1.6.1.3.1":"<dl class=\"header\">\n                <dt>description</dt>\n                <dd>It is used by Evaluate to perform the actual evaluation process for <var>module</var>, as well as recursively on all other modules in the dependency graph. The <var>stack</var> and <var>index</var> parameters, as well as <var>module</var>'s [[DFSAncestorIndex]] field, are used the same way as in InnerModuleLinking.</dd>\n              </dl>\n\n              <emu-alg><ol><li>If <var>module</var> is not a Cyclic Module Record, then<ol><li>Perform ? EvaluateModuleSync(<var>module</var>).</li><li>Return <var>index</var>.</li></ol></li><li>If <var>module</var>.[[Status]] is either <emu-const>evaluating-async</emu-const> or <emu-const>evaluated</emu-const>, then<ol><li>If <var>module</var>.[[EvaluationError]] is <emu-const>empty</emu-const>, return <var>index</var>.</li><li>Return ? <var>module</var>.[[EvaluationError]].</li></ol></li><li>If <var>module</var>.[[Status]] is <emu-const>evaluating</emu-const>, return <var>index</var>.</li><li>Assert: <var>module</var>.[[Status]] is <emu-const>linked</emu-const>.</li><li>Set <var>module</var>.[[Status]] to <emu-const>evaluating</emu-const>.</li><li>Let <var>moduleIndex</var> be <var>index</var>.</li><li>Set <var>module</var>.[[DFSAncestorIndex]] to <var>index</var>.</li><li>Set <var>module</var>.[[PendingAsyncDependencies]] to 0.</li><li>Set <var>index</var> to <var>index</var> + 1.</li><li>Append <var>module</var> to <var>stack</var>.</li><li>For each ModuleRequest Record <var>request</var> of <var>module</var>.[[RequestedModules]], do<ol><li>Let <var>requiredModule</var> be GetImportedModule(<var>module</var>, <var>request</var>).</li><li>Set <var>index</var> to ? InnerModuleEvaluation(<var>requiredModule</var>, <var>stack</var>, <var>index</var>).</li><li>If <var>requiredModule</var> is a Cyclic Module Record, then<ol><li>Assert: <var>requiredModule</var>.[[Status]] is one of <emu-const>evaluating</emu-const>, <emu-const>evaluating-async</emu-const>, or <emu-const>evaluated</emu-const>.</li><li>Assert: <var>requiredModule</var>.[[Status]] is <emu-const>evaluating</emu-const> if and only if <var>stack</var> contains <var>requiredModule</var>.</li><li>If <var>requiredModule</var>.[[Status]] is <emu-const>evaluating</emu-const>, then<ol><li>Set <var>module</var>.[[DFSAncestorIndex]] to min(<var>module</var>.[[DFSAncestorIndex]], <var>requiredModule</var>.[[DFSAncestorIndex]]).</li></ol></li><li>Else,<ol><li>Set <var>requiredModule</var> to <var>requiredModule</var>.[[CycleRoot]].</li><li>Assert: <var>requiredModule</var>.[[Status]] is either <emu-const>evaluating-async</emu-const> or <emu-const>evaluated</emu-const>.</li><li>If <var>requiredModule</var>.[[EvaluationError]] is not <emu-const>empty</emu-const>, return ? <var>requiredModule</var>.[[EvaluationError]].</li></ol></li><li>If <var>requiredModule</var>.[[AsyncEvaluationOrder]] is an integer, then<ol><li>Set <var>module</var>.[[PendingAsyncDependencies]] to <var>module</var>.[[PendingAsyncDependencies]] + 1.</li><li>Append <var>module</var> to <var>requiredModule</var>.[[AsyncParentModules]].</li></ol></li></ol></li></ol></li><li>If <var>module</var>.[[PendingAsyncDependencies]] > 0 or <var>module</var>.[[HasTLA]] is <b>true</b>, then<ol><li>Assert: <var>module</var>.[[AsyncEvaluationOrder]] is <emu-const>unset</emu-const>.</li><li>Set <var>module</var>.[[AsyncEvaluationOrder]] to IncrementModuleAsyncEvaluationCount().</li><li>If <var>module</var>.[[PendingAsyncDependencies]] = 0, perform ExecuteAsyncModule(<var>module</var>).</li></ol></li><li>Else,<ol><li>Perform ? <emu-meta effects=\"user-code\"><var>module</var>.ExecuteModule()</emu-meta>.</li></ol></li><li>Assert: <var>module</var> occurs exactly once in <var>stack</var>.</li><li>Assert: <var>module</var>.[[DFSAncestorIndex]] ≤ <var>moduleIndex</var>.</li><li>If <var>module</var>.[[DFSAncestorIndex]] = <var>moduleIndex</var>, then<ol><li>Let <var>done</var> be <b>false</b>.</li><li>Repeat, while <var>done</var> is <b>false</b>,<ol><li>Let <var>requiredModule</var> be the last element of <var>stack</var>.</li><li>Remove the last element of <var>stack</var>.</li><li>Assert: <var>requiredModule</var> is a Cyclic Module Record.</li><li>Assert: <var>requiredModule</var>.[[AsyncEvaluationOrder]] is either an integer or <emu-const>unset</emu-const>.</li><li>If <var>requiredModule</var>.[[AsyncEvaluationOrder]] is <emu-const>unset</emu-const>, set <var>requiredModule</var>.[[Status]] to <emu-const>evaluated</emu-const>.</li><li>Else, set <var>requiredModule</var>.[[Status]] to <emu-const>evaluating-async</emu-const>.</li><li>If <var>requiredModule</var> and <var>module</var> are the same Module Record, set <var>done</var> to <b>true</b>.</li><li>Set <var>requiredModule</var>.[[CycleRoot]] to <var>module</var>.</li></ol></li></ol></li><li>Return <var>index</var>.</li></ol></emu-alg>\n              <emu-note>\n                <p>A module is <emu-const>evaluating</emu-const> while it is being traversed by InnerModuleEvaluation. A module is <emu-const>evaluated</emu-const> on execution completion or <emu-const>evaluating-async</emu-const> during execution if its [[HasTLA]] field is <b>true</b> or if it has asynchronous dependencies.</p>\n              </emu-note>\n              <emu-note>\n                <p>Any modules depending on a module of an asynchronous cycle when that cycle is not <emu-const>evaluating</emu-const> will instead depend on the execution of the root of the cycle via [[CycleRoot]]. This ensures that the cycle state can be treated as a single strongly connected component through its root module state.</p>\n              </emu-note>\n            ","2.1.6.1.3.2":"<dl class=\"header\">\n              </dl>\n\n              <emu-alg><ol><li>Assert: <var>module</var>.[[Status]] is either <emu-const>evaluating</emu-const> or <emu-const>evaluating-async</emu-const>.</li><li>Assert: <var>module</var>.[[HasTLA]] is <b>true</b>.</li><li>Let <var>capability</var> be ! NewPromiseCapability(<code class=\"emu-intrinsic\">%Promise%</code>).</li><li>Let <var>fulfilledClosure</var> be a new Abstract Closure with no parameters that captures <var>module</var> and performs the following steps when called:<ol><li>Perform AsyncModuleExecutionFulfilled(<var>module</var>).</li><li>Return NormalCompletion(<b>undefined</b>).</li></ol></li><li>Let <var>onFulfilled</var> be CreateBuiltinFunction(<var>fulfilledClosure</var>, 0, <b>\"\"</b>, « »).</li><li>Let <var>rejectedClosure</var> be a new Abstract Closure with parameters (<var>error</var>) that captures <var>module</var> and performs the following steps when called:<ol><li>Perform AsyncModuleExecutionRejected(<var>module</var>, <var>error</var>).</li><li>Return NormalCompletion(<b>undefined</b>).</li></ol></li><li>Let <var>onRejected</var> be CreateBuiltinFunction(<var>rejectedClosure</var>, 0, <b>\"\"</b>, « »).</li><li>Perform PerformPromiseThen(<var>capability</var>.[[Promise]], <var>onFulfilled</var>, <var>onRejected</var>).</li><li>Perform ! <emu-meta effects=\"user-code\"><var>module</var>.ExecuteModule(<var>capability</var>)</emu-meta>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n            ","2.1.6.1.3.3":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>For each Cyclic Module Record <var>m</var> of <var>module</var>.[[AsyncParentModules]], do<ol><li>If <var>execList</var> does not contain <var>m</var> and <var>m</var>.[[CycleRoot]].[[EvaluationError]] is <emu-const>empty</emu-const>, then<ol><li>Assert: <var>m</var>.[[Status]] is <emu-const>evaluating-async</emu-const>.</li><li>Assert: <var>m</var>.[[EvaluationError]] is <emu-const>empty</emu-const>.</li><li>Assert: <var>m</var>.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: <var>m</var>.[[PendingAsyncDependencies]] > 0.</li><li>Set <var>m</var>.[[PendingAsyncDependencies]] to <var>m</var>.[[PendingAsyncDependencies]] - 1.</li><li>If <var>m</var>.[[PendingAsyncDependencies]] = 0, then<ol><li>Append <var>m</var> to <var>execList</var>.</li><li>If <var>m</var>.[[HasTLA]] is <b>false</b>, perform GatherAvailableAncestors(<var>m</var>, <var>execList</var>).</li></ol></li></ol></li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n              <emu-note>\n                <p>When an asynchronous execution for a root <var>module</var> is fulfilled, this function determines the list of modules which are able to synchronously execute together on this completion, populating them in <var>execList</var>.</p>\n              </emu-note>\n            ","2.1.6.1.3.4":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>If <var>module</var>.[[Status]] is <emu-const>evaluated</emu-const>, then<ol><li>Assert: <var>module</var>.[[EvaluationError]] is not <emu-const>empty</emu-const>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is <emu-const>evaluating-async</emu-const>.</li><li>Assert: <var>module</var>.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: <var>module</var>.[[EvaluationError]] is <emu-const>empty</emu-const>.</li><li>Set <var>module</var>.[[AsyncEvaluationOrder]] to <emu-const>done</emu-const>.</li><li>Set <var>module</var>.[[Status]] to <emu-const>evaluated</emu-const>.</li><li>If <var>module</var>.[[TopLevelCapability]] is not <emu-const>empty</emu-const>, then<ol><li>Assert: <var>module</var>.[[CycleRoot]] and <var>module</var> are the same Module Record.</li><li>Perform ! Call(<var>module</var>.[[TopLevelCapability]].[[Resolve]], <b>undefined</b>, « <b>undefined</b> »).</li></ol></li><li>Let <var>execList</var> be a new empty List.</li><li>Perform GatherAvailableAncestors(<var>module</var>, <var>execList</var>).</li><li>Assert: All elements of <var>execList</var> have their [[AsyncEvaluationOrder]] field set to an integer, [[PendingAsyncDependencies]] field set to 0, and [[EvaluationError]] field set to <emu-const>empty</emu-const>.</li><li>Let <var>sortedExecList</var> be a List whose elements are the elements of <var>execList</var>, sorted by their [[AsyncEvaluationOrder]] field in ascending order.</li><li>For each Cyclic Module Record <var>m</var> of <var>sortedExecList</var>, do<ol><li>If <var>m</var>.[[Status]] is <emu-const>evaluated</emu-const>, then<ol><li>Assert: <var>m</var>.[[EvaluationError]] is not <emu-const>empty</emu-const>.</li></ol></li><li>Else if <var>m</var>.[[HasTLA]] is <b>true</b>, then<ol><li>Perform ExecuteAsyncModule(<var>m</var>).</li></ol></li><li>Else,<ol><li>Let <var>result</var> be Completion(<emu-meta effects=\"user-code\"><var>m</var>.ExecuteModule()</emu-meta>).</li><li>If <var>result</var> is an abrupt completion, then<ol><li>Perform AsyncModuleExecutionRejected(<var>m</var>, <var>result</var>.[[Value]]).</li></ol></li><li>Else,<ol><li>Set <var>m</var>.[[AsyncEvaluationOrder]] to <emu-const>done</emu-const>.</li><li>Set <var>m</var>.[[Status]] to <emu-const>evaluated</emu-const>.</li><li>If <var>m</var>.[[TopLevelCapability]] is not <emu-const>empty</emu-const>, then<ol><li>Assert: <var>m</var>.[[CycleRoot]] and <var>m</var> are the same Module Record.</li><li>Perform ! Call(<var>m</var>.[[TopLevelCapability]].[[Resolve]], <b>undefined</b>, « <b>undefined</b> »).</li></ol></li></ol></li></ol></li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n            ","2.1.6.1.3.5":"<dl class=\"header\">\n              </dl>\n              <emu-alg><ol><li>If <var>module</var>.[[Status]] is <emu-const>evaluated</emu-const>, then<ol><li>Assert: <var>module</var>.[[EvaluationError]] is not <emu-const>empty</emu-const>.</li><li>Return <emu-const>unused</emu-const>.</li></ol></li><li>Assert: <var>module</var>.[[Status]] is <emu-const>evaluating-async</emu-const>.</li><li>Assert: <var>module</var>.[[AsyncEvaluationOrder]] is an integer.</li><li>Assert: <var>module</var>.[[EvaluationError]] is <emu-const>empty</emu-const>.</li><li>Set <var>module</var>.[[EvaluationError]] to ThrowCompletion(<var>error</var>).</li><li>Set <var>module</var>.[[Status]] to <emu-const>evaluated</emu-const>.</li><li>Set <var>module</var>.[[AsyncEvaluationOrder]] to <emu-const>done</emu-const>.</li><li>NOTE: <var>module</var>.[[AsyncEvaluationOrder]] is set to <emu-const>done</emu-const> for symmetry with AsyncModuleExecutionFulfilled. In InnerModuleEvaluation, the value of a module's [[AsyncEvaluationOrder]] internal slot is unused when its [[EvaluationError]] internal slot is not <emu-const>empty</emu-const>.</li><li>If <var>module</var>.[[TopLevelCapability]] is not <emu-const>empty</emu-const>, then<ol><li>Assert: <var>module</var>.[[CycleRoot]] and <var>module</var> are the same Module Record.</li><li>Perform ! Call(<var>module</var>.[[TopLevelCapability]].[[Reject]], <b>undefined</b>, « <var>error</var> »).</li></ol></li><li>For each Cyclic Module Record <var>m</var> of <var>module</var>.[[AsyncParentModules]], do<ol><li>Perform AsyncModuleExecutionRejected(<var>m</var>, <var>error</var>).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n            ","2.1.6.2":"<p>This non-normative section gives a series of examples of the linking and evaluation of a few common module graphs, with a specific focus on how errors can occur.</p>\n\n          <p>First consider the following simple module graph:</p>\n\n          <emu-figure id=\"figure-module-graph-simple\" caption=\"A simple module graph\">\n            <img alt=\"A module graph in which module A depends on module B, and module B depends on module C\" width=\"60\" height=\"198\" src=\"img/module-graph-simple.svg\">\n          </emu-figure>\n\n          <p>Let's first assume that there are no error conditions. When a host first calls <var>A</var>.LoadRequestedModules(), this will complete successfully by assumption, and recursively load the dependencies of <var>B</var> and <var>C</var> as well (respectively, <var>C</var> and none), and then set <var>A</var>.[[Status]] = <var>B</var>.[[Status]] = <var>C</var>.[[Status]] = <emu-const>unlinked</emu-const>. Then, when the host calls <var>A</var>.Link(), it will complete successfully (again by assumption) such that <var>A</var>.[[Status]] = <var>B</var>.[[Status]] = <var>C</var>.[[Status]] = <emu-const>linked</emu-const>. These preparatory steps can be performed at any time. Later, when the host is ready to incur any possible side effects of the modules, it can call <var>A</var>.Evaluate(), which will complete successfully, returning a Promise resolving to <b>undefined</b> (again by assumption), recursively having evaluated first <var>C</var> and then <var>B</var>. Each module's [[Status]] at this point will be <emu-const>evaluated</emu-const>.</p>\n\n          <p>Consider then cases involving linking errors, after a successful call to <var>A</var>.LoadRequestedModules(). If InnerModuleLinking of <var>C</var> succeeds but, thereafter, fails for <var>B</var>, for example because it imports something that <var>C</var> does not provide, then the original <var>A</var>.Link() will fail, and both <var>A</var> and <var>B</var>'s [[Status]] remain <emu-const>unlinked</emu-const>. <var>C</var>'s [[Status]] has become <emu-const>linked</emu-const>, though.</p>\n\n          <p>Finally, consider a case involving evaluation errors after a successful call to Link(). If InnerModuleEvaluation of <var>C</var> succeeds but, thereafter, fails for <var>B</var>, for example because <var>B</var> contains code that throws an exception, then the original <var>A</var>.Evaluate() will fail, returning a rejected Promise. The resulting exception will be recorded in both <var>A</var> and <var>B</var>'s [[EvaluationError]] fields, and their [[Status]] will become <emu-const>evaluated</emu-const>. <var>C</var> will also become <emu-const>evaluated</emu-const> but, in contrast to <var>A</var> and <var>B</var>, will remain without an [[EvaluationError]], as it successfully completed evaluation. Storing the exception ensures that any time a host tries to reuse <var>A</var> or <var>B</var> by calling their Evaluate() method, it will encounter the same exception. (Hosts are not required to reuse Cyclic Module Records; similarly, hosts are not required to expose the exception objects thrown by these methods. However, the specification enables such uses.)</p>\n\n          <p>Now consider a different type of error condition:</p>\n\n          <emu-figure id=\"figure-module-graph-missing\" caption=\"A module graph with an unresolvable module\">\n            <img alt=\"A module graph in which module A depends on a missing (unresolvable) module, represented by ???\" width=\"60\" height=\"121\" src=\"img/module-graph-missing.svg\">\n          </emu-figure>\n\n          <p>In this scenario, module <var>A</var> declares a dependency on some other module, but no Module Record exists for that module, i.e. HostLoadImportedModule calls FinishLoadingImportedModule with an exception when asked for it. This could occur for a variety of reasons, such as the corresponding resource not existing, or the resource existing but ParseModule returning some errors when trying to parse the resulting source text. Hosts can choose to expose the cause of failure via the completion they pass to FinishLoadingImportedModule. In any case, this exception causes a loading failure, which results in <var>A</var>'s [[Status]] remaining <emu-const>new</emu-const>.</p>\n\n          <p>The difference here between loading, linking and evaluation errors is due to the following characteristic:</p>\n          <ul>\n            <li>Evaluation must be only performed once, as it can cause side effects; it is thus important to remember whether evaluation has already been performed, even if unsuccessfully. (In the error case, it makes sense to also remember the exception because otherwise subsequent Evaluate() calls would have to synthesize a new one.)</li>\n            <li>Linking, on the other hand, is side-effect-free, and thus even if it fails, it can be retried at a later time with no issues.</li>\n            <li>Loading closely interacts with the host, and it may be desirable for some of them to allow users to retry failed loads (for example, if the failure is caused by temporarily bad network conditions).</li>\n          </ul>\n\n          <p>Now, consider a module graph with a cycle:</p>\n\n          <emu-figure id=\"figure-module-graph-cycle\" caption=\"A cyclic module graph\">\n            <img alt=\"A module graph in which module A depends on module B and C, but module B also depends on module A\" width=\"181\" height=\"121\" src=\"img/module-graph-cycle.svg\">\n          </emu-figure>\n\n          <p>Here we assume that the entry point is module <var>A</var>, so that the host proceeds by calling <var>A</var>.LoadRequestedModules(), which performs InnerModuleLoading on <var>A</var>. This in turn calls InnerModuleLoading on <var>B</var> and <var>C</var>. Because of the cycle, this again triggers InnerModuleLoading on <var>A</var>, but at this point it is a no-op since <var>A</var>'s dependencies loading has already been triggered during this LoadRequestedModules process. When all the modules in the graph have been successfully loaded, their [[Status]] transitions from <emu-const>new</emu-const> to <emu-const>unlinked</emu-const> at the same time.</p>\n\n          <p>Then the host proceeds by calling <var>A</var>.Link(), which performs InnerModuleLinking on <var>A</var>. This in turn calls InnerModuleLinking on <var>B</var>. Because of the cycle, this again triggers InnerModuleLinking on <var>A</var>, but at this point it is a no-op since <var>A</var>.[[Status]] is already <emu-const>linking</emu-const>. <var>B</var>.[[Status]] itself remains <emu-const>linking</emu-const> when control gets back to <var>A</var> and InnerModuleLinking is triggered on <var>C</var>. After this returns with <var>C</var>.[[Status]] being <emu-const>linked</emu-const>, both <var>A</var> and <var>B</var> transition from <emu-const>linking</emu-const> to <emu-const>linked</emu-const> together; this is by design, since they form a strongly connected component. It's possible to transition the status of modules in the same SCC at the same time because during this phase the module graph is traversed with a depth-first search.</p>\n\n          <p>An analogous story occurs for the evaluation phase of a cyclic module graph, in the success case.</p>\n\n          <p>Now consider a case where <var>A</var> has a linking error; for example, it tries to import a binding from <var>C</var> that does not exist. In that case, the above steps still occur, including the early return from the second call to InnerModuleLinking on <var>A</var>. However, once we unwind back to the original InnerModuleLinking on <var>A</var>, it fails during InitializeEnvironment, namely right after <var>C</var>.ResolveExport(). The thrown <b>SyntaxError</b> exception propagates up to <var>A</var>.Link, which resets all modules that are currently on its <var>stack</var> (these are always exactly the modules that are still <emu-const>linking</emu-const>). Hence both <var>A</var> and <var>B</var> become <emu-const>unlinked</emu-const>. Note that <var>C</var> is left as <emu-const>linked</emu-const>.</p>\n\n          <p>Alternatively, consider a case where <var>A</var> has an evaluation error; for example, its source code throws an exception. In that case, the evaluation-time analogue of the above steps still occurs, including the early return from the second call to InnerModuleEvaluation on <var>A</var>. However, once we unwind back to the original InnerModuleEvaluation on <var>A</var>, it fails by assumption. The exception thrown propagates up to <var>A</var>.Evaluate(), which records the error in all modules that are currently on its <var>stack</var> (i.e., the modules that are still <emu-const>evaluating</emu-const>) as well as via [[AsyncParentModules]], which form a chain for modules which contain or depend on top-level <code>await</code> through the whole dependency graph through the AsyncModuleExecutionRejected algorithm. Hence both <var>A</var> and <var>B</var> become <emu-const>evaluated</emu-const> and the exception is recorded in both <var>A</var> and <var>B</var>'s [[EvaluationError]] fields, while <var>C</var> is left as <emu-const>evaluated</emu-const> with no [[EvaluationError]].</p>\n\n          <p>Lastly, consider a module graph with a cycle, where all modules complete asynchronously:</p>\n          <emu-figure id=\"figure-module-graph-cycle-async\" caption=\"An asynchronous cyclic module graph\">\n            <img alt=\"A module graph in which module A depends on module B and C, module B depends on module D, module C depends on module D and E, and module D depends on module A\" width=\"241\" height=\"211\" src=\"img/module-graph-cycle-async.svg\">\n          </emu-figure>\n          <p>Loading and linking happen as before, and all modules end up with [[Status]] set to <emu-const>linked</emu-const>.</p>\n\n          <p>Calling <var>A</var>.Evaluate() calls InnerModuleEvaluation on <var>A</var>, <var>B</var>, and <var>D</var>, which all transition to <emu-const>evaluating</emu-const>. Then InnerModuleEvaluation is called on <var>A</var> again, which is a no-op because it is already <emu-const>evaluating</emu-const>. At this point, <var>D</var>.[[PendingAsyncDependencies]] is 0, so ExecuteAsyncModule(<var>D</var>) is called and we call <var>D</var>.ExecuteModule with a new PromiseCapability tracking the asynchronous execution of <var>D</var>. We unwind back to the InnerModuleEvaluation on <var>B</var>, setting <var>B</var>.[[PendingAsyncDependencies]] to 1 and <var>B</var>.[[AsyncEvaluationOrder]] to 1. We unwind back to the original InnerModuleEvaluation on <var>A</var>, setting <var>A</var>.[[PendingAsyncDependencies]] to 1. In the next iteration of the loop over <var>A</var>'s dependencies, we call InnerModuleEvaluation on <var>C</var> and thus on <var>D</var> (again a no-op) and <var>E</var>. As <var>E</var> has no dependencies and is not part of a cycle, we call ExecuteAsyncModule(<var>E</var>) in the same manner as <var>D</var> and <var>E</var> is immediately removed from the stack. We unwind once more to the InnerModuleEvaluation on <var>C</var>, setting <var>C</var>.[[AsyncEvaluationOrder]] to 3. Now we finish the loop over <var>A</var>'s dependencies, set <var>A</var>.[[AsyncEvaluationOrder]] to 4, and remove the entire strongly connected component from the stack, transitioning all of the modules to <emu-const>evaluating-async</emu-const> at once. At this point, the fields of the modules are as given in table-module-graph-cycle-async-fields-1.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-1\" caption=\"Module fields after the initial Evaluate() call\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                  <th><var>B</var></th>\n                  <th><var>C</var></th>\n                  <th><var>D</var></th>\n                  <th><var>E</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n                <td>4</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluating-async</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>1</td>\n                <td>3</td>\n                <td>0</td>\n                <td>2</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« <var>A</var> »</td>\n                <td>« <var>A</var> »</td>\n                <td>« <var>B</var>, <var>C</var> »</td>\n                <td>« <var>C</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>2 (<var>B</var> and <var>C</var>)</td>\n                <td>1 (<var>D</var>)</td>\n                <td>2 (<var>D</var> and <var>E</var>)</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Let us assume that <var>E</var> finishes executing first. When that happens, AsyncModuleExecutionFulfilled is called, <var>E</var>.[[Status]] is set to <emu-const>evaluated</emu-const> and <var>C</var>.[[PendingAsyncDependencies]] is decremented to become 1. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-2.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-2\" caption=\"Module fields after module _E_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>C</var></th>\n                  <th><var>E</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>4</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>3</td>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« <var>A</var> »</td>\n                <td>« <var>C</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (<var>D</var>)</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p><var>D</var> is next to finish (as it was the only module that was still executing). When that happens, AsyncModuleExecutionFulfilled is called again and <var>D</var>.[[Status]] is set to <emu-const>evaluated</emu-const>. Its ancestors available for execution are <var>B</var> (whose [[AsyncEvaluationOrder]] is 1) and <var>C</var> (whose [[AsyncEvaluationOrder]] is 3), thus <var>B</var> will be handled first: <var>B</var>.[[PendingAsyncDependencies]] is decremented to become 0, ExecuteAsyncModule is called on <var>B</var>, and it starts executing. <var>C</var>.[[PendingAsyncDependencies]] is also decremented to become 0, and <var>C</var> starts executing (potentially in parallel to <var>B</var> if <var>B</var> contains an <code>await</code>). The fields of the updated modules are as given in table-module-graph-cycle-async-fields-3.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-3\" caption=\"Module fields after module _D_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>B</var></th>\n                  <th><var>C</var></th>\n                  <th><var>D</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>1</td>\n                <td>3</td>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« <var>A</var> »</td>\n                <td>« <var>A</var> »</td>\n                <td>« <var>B</var>, <var>C</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Let us assume that <var>C</var> finishes executing next. When that happens, AsyncModuleExecutionFulfilled is called again, <var>C</var>.[[Status]] is set to <emu-const>evaluated</emu-const> and <var>A</var>.[[PendingAsyncDependencies]] is decremented to become 1. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-4.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-4\" caption=\"Module fields after module _C_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                  <th><var>C</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« <var>A</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (<var>B</var>)</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Then, <var>B</var> finishes executing. When that happens, AsyncModuleExecutionFulfilled is called again and <var>B</var>.[[Status]] is set to <emu-const>evaluated</emu-const>. <var>A</var>.[[PendingAsyncDependencies]] is decremented to become 0, so ExecuteAsyncModule is called and it starts executing. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-5.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-5\" caption=\"Module fields after module _B_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                  <th><var>B</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluating-async</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« <var>A</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Finally, <var>A</var> finishes executing. When that happens, AsyncModuleExecutionFulfilled is called again and <var>A</var>.[[Status]] is set to <emu-const>evaluated</emu-const>. At this point, the Promise in <var>A</var>.[[TopLevelCapability]] (which was returned from <var>A</var>.Evaluate()) is resolved, and this concludes the handling of this module graph. The fields of the updated module are as given in table-module-graph-cycle-async-fields-6.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-6\" caption=\"Module fields after module _A_ finishes executing\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Alternatively, consider a failure case where <var>C</var> fails execution and returns an error before <var>B</var> has finished executing. When that happens, AsyncModuleExecutionRejected is called, which sets <var>C</var>.[[Status]] to <emu-const>evaluated</emu-const> and <var>C</var>.[[EvaluationError]] to the error. It then propagates this error to all of the AsyncParentModules by performing AsyncModuleExecutionRejected on each of them. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-7.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-7\" caption=\"Module fields after module _C_ finishes with an error\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                  <th><var>C</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluated</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td><emu-const>done</emu-const></td>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« <var>A</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>1 (<var>B</var>)</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n                <td><emu-const>empty</emu-const></td>\n                <td><var>C</var>'s evaluation error</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p><var>A</var> will be rejected with the same error as <var>C</var> since <var>C</var> will call AsyncModuleExecutionRejected on <var>A</var> with <var>C</var>'s error. <var>A</var>.[[Status]] is set to <emu-const>evaluated</emu-const>. At this point the Promise in <var>A</var>.[[TopLevelCapability]] (which was returned from <var>A</var>.Evaluate()) is rejected. The fields of the updated module are as given in table-module-graph-cycle-async-fields-8.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-8\" caption=\"Module fields after module _A_ is rejected\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td><emu-const>done</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n\n                <td><var>C</var>'s Evaluation Error</td>\n              </tr>\n            </table>\n          </emu-table>\n\n          <p>Then, <var>B</var> finishes executing without an error. When that happens, AsyncModuleExecutionFulfilled is called again and <var>B</var>.[[Status]] is set to <emu-const>evaluated</emu-const>. GatherAvailableAncestors is called on <var>B</var>. However, <var>A</var>.[[CycleRoot]] is <var>A</var> which has an evaluation error, so it will not be added to the returned <var>sortedExecList</var> and AsyncModuleExecutionFulfilled will return without further processing. Any future importer of <var>B</var> will resolve the rejection of <var>B</var>.[[CycleRoot]].[[EvaluationError]] from the evaluation error from <var>C</var> that was set on the cycle root <var>A</var>. The fields of the updated modules are as given in table-module-graph-cycle-async-fields-9.</p>\n\n          <emu-table id=\"table-module-graph-cycle-async-fields-9\" caption=\"Module fields after module _B_ finishes executing in an erroring graph\">\n            <table>\n              <thead>\n                <tr>\n                  <th class=\"corner-cell\">\n                    <span class=\"column\">Field</span>\n                    <div class=\"slash\">\n                    </div>\n                    <span class=\"row\">Module</span>\n                  </th>\n                  <th><var>A</var></th>\n                  <th><var>B</var></th>\n                </tr>\n              </thead>\n              <tr>\n                <th>[[DFSAncestorIndex]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[Status]]</th>\n                <td><emu-const>evaluated</emu-const></td>\n                <td><emu-const>evaluated</emu-const></td>\n              </tr>\n              <tr>\n                <th>[[AsyncEvaluationOrder]]</th>\n                <td>4</td>\n                <td>1</td>\n              </tr>\n              <tr>\n                <th>[[AsyncParentModules]]</th>\n                <td>« »</td>\n                <td>« <var>A</var> »</td>\n              </tr>\n              <tr>\n                <th>[[PendingAsyncDependencies]]</th>\n                <td>0</td>\n                <td>0</td>\n              </tr>\n              <tr>\n                <th>[[EvaluationError]]</th>\n                <td><var>C</var>'s Evaluation Error</td>\n                <td><emu-const>empty</emu-const></td>\n              </tr>\n            </table>\n          </emu-table>\n        ","2.1.7":"<p>A <dfn id=\"sourctextmodule-record\" variants=\"Source Text Module Records\">Source Text Module Record</dfn> is used to represent information about a module that was defined from ECMAScript source text (11) that was parsed using the goal symbol <emu-nt>Module</emu-nt>. Its fields contain digested information about the names that are imported and exported by the module, and its concrete methods use these digests to link and evaluate the module.</p>\n\n        <p>A Source Text Module Record can exist in a module graph with other subclasses of the abstract Module Record type, and can participate in cycles with other subclasses of the Cyclic Module Record type.</p>\n\n        <p>In addition to the fields defined in table-cyclic-module-fields, Source Text Module Records have the additional fields listed in table-additional-fields-of-source-text-module-records. Each of these fields is initially set in ParseModule.</p>\n        <emu-table id=\"table-additional-fields-of-source-text-module-records\" caption=\"Additional Fields of Source Text Module Records\" oldids=\"table-38\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ECMAScriptCode]]\n              </td>\n              <td>\n                a Parse Node\n              </td>\n              <td>\n                The result of parsing the source text of this module using <emu-nt>Module</emu-nt> as the goal symbol.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[Context]]\n              </td>\n              <td>\n                an ECMAScript code execution context or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                The execution context associated with this module. It is <emu-const>empty</emu-const> until the module's environment has been initialized.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportMeta]]\n              </td>\n              <td>\n                an Object or <emu-const>empty</emu-const>\n              </td>\n              <td>\n                An object exposed through the <code>import.meta</code> meta property. It is <emu-const>empty</emu-const> until it is accessed by ECMAScript code.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportEntries]]\n              </td>\n              <td>\n                a List of ImportEntry Records\n              </td>\n              <td>\n                A List of ImportEntry records derived from the code of this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to declarations that occur within the module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[IndirectExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to reexported imports that occur within the module or exports from <code>export * as namespace</code> declarations.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[StarExportEntries]]\n              </td>\n              <td>\n                a List of ExportEntry Records\n              </td>\n              <td>\n                A List of ExportEntry records derived from the code of this module that correspond to <code>export *</code> declarations that occur within the module, not including <code>export * as namespace</code> declarations.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <p>An <dfn id=\"importentry-record\" variants=\"ImportEntry Records\">ImportEntry Record</dfn> is a Record that digests information about a single declarative import. Each ImportEntry Record has the fields defined in table-importentry-record-fields:</p>\n        <emu-table id=\"table-importentry-record-fields\" caption=\"ImportEntry Record Fields\" oldids=\"table-39\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ModuleRequest]]\n              </td>\n              <td>\n                a ModuleRequest Record\n              </td>\n              <td>\n                ModuleRequest Record representing the <emu-nt>ModuleSpecifier</emu-nt> and import attributes of the <emu-nt>ImportDeclaration</emu-nt>.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportName]]\n              </td>\n              <td>\n                a String or <emu-const>namespace</emu-const>\n              </td>\n              <td>\n                The name under which the desired binding is exported by the module identified by [[ModuleRequest]]. The value <emu-const>namespace</emu-const> indicates that the import request is for the target module's namespace object.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalName]]\n              </td>\n              <td>\n                a String\n              </td>\n              <td>\n                The name that is used to locally access the imported value from within the importing module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-note>\n          <p>table-import-forms-mapping-to-importentry-records gives examples of ImportEntry records fields used to represent the syntactic import forms:</p>\n          <emu-table id=\"table-import-forms-mapping-to-importentry-records\" caption=\"Import Forms Mappings to ImportEntry Records\" informative oldids=\"table-40\">\n            <table>\n              <thead>\n                <tr>\n                  <th>\n                    Import Statement Form\n                  </th>\n                  <th>\n                    [[ModuleRequest]]\n                  </th>\n                  <th>\n                    [[ImportName]]\n                  </th>\n                  <th>\n                    [[LocalName]]\n                  </th>\n                </tr>\n              </thead>\n              <tr>\n                <td>\n                  <code>import v from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <b>\"default\"</b>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>import * as ns from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <emu-const>namespace</emu-const>\n                </td>\n                <td>\n                  <b>\"ns\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>import {x} from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>import {x as v} from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>import \"mod\";</code>\n                </td>\n                <td colspan=\"3\">\n                  An ImportEntry Record is not created.\n                </td>\n              </tr>\n            </table>\n          </emu-table>\n        </emu-note>\n        <p>An <dfn id=\"exportentry-record\" variants=\"ExportEntry Records\">ExportEntry Record</dfn> is a Record that digests information about a single declarative export. Each ExportEntry Record has the fields defined in table-exportentry-records:</p>\n        <emu-table id=\"table-exportentry-records\" caption=\"ExportEntry Record Fields\" oldids=\"table-41\">\n          <table>\n            <thead>\n              <tr>\n                <th>\n                  Field Name\n                </th>\n                <th>\n                  Value Type\n                </th>\n                <th>\n                  Meaning\n                </th>\n              </tr>\n            </thead>\n            <tr>\n              <td>\n                [[ExportName]]\n              </td>\n              <td>\n                a String or <b>null</b>\n              </td>\n              <td>\n                The name used to export this binding by this module.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ModuleRequest]]\n              </td>\n              <td>\n                a ModuleRequest Record or <b>null</b>\n              </td>\n              <td>\n                The ModuleRequest Record representing the <emu-nt>ModuleSpecifier</emu-nt> and import attributes of the <emu-nt>ExportDeclaration</emu-nt>. <b>null</b> if the <emu-nt>ExportDeclaration</emu-nt> does not have a <emu-nt>ModuleSpecifier</emu-nt>.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[ImportName]]\n              </td>\n              <td>\n                a String, <b>null</b>, <emu-const>namespace</emu-const>, or <emu-const>all-but-default</emu-const>\n              </td>\n              <td>\n                The name under which the desired binding is exported by the module identified by [[ModuleRequest]]. <b>null</b> if the <emu-nt>ExportDeclaration</emu-nt> does not have a <emu-nt>ModuleSpecifier</emu-nt>. <emu-const>namespace</emu-const> is used for <code>export * as ns from \"mod\"</code> declarations. <emu-const>all-but-default</emu-const> is used for <code>export * from \"mod\"</code> declarations.\n              </td>\n            </tr>\n            <tr>\n              <td>\n                [[LocalName]]\n              </td>\n              <td>\n                a String or <b>null</b>\n              </td>\n              <td>\n                The name that is used to locally access the exported value from within the importing module. <b>null</b> if the exported value is not locally accessible from within the module.\n              </td>\n            </tr>\n          </table>\n        </emu-table>\n        <emu-note>\n          <p>table-export-forms-mapping-to-exportentry-records gives examples of the ExportEntry record fields used to represent the syntactic export forms:</p>\n          <emu-table id=\"table-export-forms-mapping-to-exportentry-records\" caption=\"Export Forms Mappings to ExportEntry Records\" informative oldids=\"table-42\">\n            <table>\n              <thead>\n                <tr>\n                  <th>\n                    Export Statement Form\n                  </th>\n                  <th>\n                    [[ExportName]]\n                  </th>\n                  <th>\n                    [[ModuleRequest]]\n                  </th>\n                  <th>\n                    [[ImportName]]\n                  </th>\n                  <th>\n                    [[LocalName]]\n                  </th>\n                </tr>\n              </thead>\n              <tr>\n                <td>\n                  <code>export var v;</code>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export default function f() {}</code>\n                </td>\n                <td>\n                  <b>\"default\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"f\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export default function () {}</code>\n                </td>\n                <td>\n                  <b>\"default\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"\\</b>default\\<b>\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export default 42;</code>\n                </td>\n                <td>\n                  <b>\"default\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"\\</b>default\\<b>\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export {x};</code>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export {v as x};</code>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export {x} from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export {v as x} from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"x\"</b>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <b>\"v\"</b>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export * from \"mod\";</code>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <emu-const>all-but-default</emu-const>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n              </tr>\n              <tr>\n                <td>\n                  <code>export * as ns from \"mod\";</code>\n                </td>\n                <td>\n                  <b>\"ns\"</b>\n                </td>\n                <td>\n                  <b>\"mod\"</b>\n                </td>\n                <td>\n                  <emu-const>namespace</emu-const>\n                </td>\n                <td>\n                  <b>null</b>\n                </td>\n              </tr>\n            </table>\n          </emu-table>\n        </emu-note>\n        <p>The following definitions specify the required concrete methods and other abstract operations for Source Text Module Records</p>\n\n        ","2.1.7.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It creates a Source Text Module Record based upon the result of parsing <var>sourceText</var> as a <emu-nt>Module</emu-nt>.</dd>\n          </dl>\n          <emu-alg><ol><li>Let <var>body</var> be ParseText(<var>sourceText</var>, <emu-nt>Module</emu-nt>).</li><li>If <var>body</var> is a List of errors, return <var>body</var>.</li><li>Let <var>requestedModules</var> be the ModuleRequests of <var>body</var>.</li><li>Let <var>importEntries</var> be the ImportEntries of <var>body</var>.</li><li>Let <var>importedBoundNames</var> be ImportedLocalNames(<var>importEntries</var>).</li><li>Let <var>indirectExportEntries</var> be a new empty List.</li><li>Let <var>localExportEntries</var> be a new empty List.</li><li>Let <var>starExportEntries</var> be a new empty List.</li><li>Let <var>exportEntries</var> be the ExportEntries of <var>body</var>.</li><li>For each ExportEntry Record <var>ee</var> of <var>exportEntries</var>, do<ol><li>If <var>ee</var>.[[ModuleRequest]] is <b>null</b>, then<ol><li>If <var>importedBoundNames</var> does not contain <var>ee</var>.[[LocalName]], then<ol><li>Append <var>ee</var> to <var>localExportEntries</var>.</li></ol></li><li>Else,<ol><li>NOTE: When exporting a binding or namespace object which was originally imported from another module, the ExportEntry Record is rewritten to match the form it would have if the binding or namespace object had been re-exported directly from the original module rather than imported then exported. This allows conflicts which arise from exporting the same binding or namespace twice under the same name through <code>export * from</code> to be ignored rather than being treated as ambiguous in step step-resolveexport-conflict of <emu-xref href=\"#sec-resolveexport\">the ResolveExport concrete method of Source Text Module Records</emu-xref>.</li><li>Let <var>ie</var> be the element of <var>importEntries</var> whose [[LocalName]] is <var>ee</var>.[[LocalName]].</li><li>Append the ExportEntry Record { [[ModuleRequest]]: <var>ie</var>.[[ModuleRequest]], [[ImportName]]: <var>ie</var>.[[ImportName]], [[LocalName]]: <b>null</b>, [[ExportName]]: <var>ee</var>.[[ExportName]] } to <var>indirectExportEntries</var>.</li></ol></li></ol></li><li>Else if <var>ee</var>.[[ImportName]] is <emu-const>all-but-default</emu-const>, then<ol><li>Assert: <var>ee</var>.[[ExportName]] is <b>null</b>.</li><li>Append <var>ee</var> to <var>starExportEntries</var>.</li></ol></li><li>Else,<ol><li>Append <var>ee</var> to <var>indirectExportEntries</var>.</li></ol></li></ol></li><li>Let <var>async</var> be <var>body</var> Contains <code>await</code>.</li><li>Return Source Text Module Record { [[Realm]]: <var>realm</var>, [[Environment]]: <emu-const>empty</emu-const>, [[Namespace]]: <emu-const>empty</emu-const>, [[CycleRoot]]: <emu-const>empty</emu-const>, [[HasTLA]]: <var>async</var>, [[AsyncEvaluationOrder]]: <emu-const>unset</emu-const>, [[TopLevelCapability]]: <emu-const>empty</emu-const>, [[AsyncParentModules]]: « », [[PendingAsyncDependencies]]: <emu-const>empty</emu-const>, [[Status]]: <emu-const>new</emu-const>, [[EvaluationError]]: <emu-const>empty</emu-const>, [[HostDefined]]: <var>hostDefined</var>, [[ECMAScriptCode]]: <var>body</var>, [[Context]]: <emu-const>empty</emu-const>, [[ImportMeta]]: <emu-const>empty</emu-const>, [[RequestedModules]]: <var>requestedModules</var>, [[LoadedModules]]: « », [[ImportEntries]]: <var>importEntries</var>, [[LocalExportEntries]]: <var>localExportEntries</var>, [[IndirectExportEntries]]: <var>indirectExportEntries</var>, [[StarExportEntries]]: <var>starExportEntries</var>, [[DFSAncestorIndex]]: <emu-const>empty</emu-const> }.</li></ol></emu-alg>\n          <emu-note>\n            <p>An implementation may parse module source text and analyse it for Early Error conditions prior to the evaluation of ParseModule for that module source text. However, the reporting of any errors must be deferred until the point where this specification actually performs ParseModule upon that source text.</p>\n          </emu-note>\n        ","2.1.7.2":"<p>The following are the concrete methods for Source Text Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.7.2.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record <var>module</var></dd>\n            </dl>\n            <emu-alg><ol><li>Assert: <var>module</var>.[[Status]] is not <emu-const>new</emu-const>.</li><li>If <var>exportStarSet</var> is not present, set <var>exportStarSet</var> to a new empty List.</li><li>If <var>exportStarSet</var> contains <var>module</var>, then<ol><li>Assert: We've reached the starting point of an <code>export *</code> circularity.</li><li>Return a new empty List.</li></ol></li><li>Append <var>module</var> to <var>exportStarSet</var>.</li><li>Let <var>exportedNames</var> be a new empty List.</li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[LocalExportEntries]], do<ol><li>Assert: <var>module</var> provides the direct binding for this export.</li><li>Assert: <var>e</var>.[[ExportName]] is not <b>null</b>.</li><li>Append <var>e</var>.[[ExportName]] to <var>exportedNames</var>.</li></ol></li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[IndirectExportEntries]], do<ol><li>Assert: <var>module</var> imports a specific binding for this export.</li><li>Assert: <var>e</var>.[[ExportName]] is not <b>null</b>.</li><li>Append <var>e</var>.[[ExportName]] to <var>exportedNames</var>.</li></ol></li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[StarExportEntries]], do<ol><li>Assert: <var>e</var>.[[ModuleRequest]] is not <b>null</b>.</li><li>Let <var>requestedModule</var> be GetImportedModule(<var>module</var>, <var>e</var>.[[ModuleRequest]]).</li><li>Let <var>starNames</var> be <var>requestedModule</var>.GetExportedNames(<var>exportStarSet</var>).</li><li>For each element <var>n</var> of <var>starNames</var>, do<ol><li>If <var>n</var> is not <b>\"default\"</b>, then<ol><li>If <var>exportedNames</var> does not contain <var>n</var>, then<ol><li>Append <var>n</var> to <var>exportedNames</var>.</li></ol></li></ol></li></ol></li></ol></li><li>Return <var>exportedNames</var>.</li></ol></emu-alg>\n            <emu-note>\n              <p>GetExportedNames does not filter out or throw an exception for names that have ambiguous star export bindings.</p>\n            </emu-note>\n          ","2.1.7.2.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record <var>module</var></dd>\n\n              <dt>description</dt>\n              <dd>\n                <p>ResolveExport attempts to resolve an imported binding to the actual defining module and local binding name. The defining module may be the module represented by the Module Record this method was invoked on or some other module that is imported by that module. The parameter <var>resolveSet</var> is used to detect unresolved circular import/export paths. If a pair consisting of specific Module Record and <var>exportName</var> is reached that is already in <var>resolveSet</var>, an import circularity has been encountered. Before recursively calling ResolveExport, a pair consisting of <var>module</var> and <var>exportName</var> is added to <var>resolveSet</var>.</p>\n                <p>If a defining module is found, a ResolvedBinding Record { [[Module]], [[BindingName]] } is returned. This record identifies the resolved binding of the originally requested export, unless this is the export of a namespace with no local binding. In this case, [[BindingName]] will be set to <emu-const>namespace</emu-const>. If no definition was found or the request is found to be circular, <b>null</b> is returned. If the request is found to be ambiguous, <emu-const>ambiguous</emu-const> is returned.</p>\n              </dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: <var>module</var>.[[Status]] is not <emu-const>new</emu-const>.</li><li>If <var>resolveSet</var> is not present, set <var>resolveSet</var> to a new empty List.</li><li>For each Record { [[Module]], [[ExportName]] } <var>r</var> of <var>resolveSet</var>, do<ol><li>If <var>module</var> and <var>r</var>.[[Module]] are the same Module Record and <var>exportName</var> is <var>r</var>.[[ExportName]], then<ol><li>Assert: This is a circular import request.</li><li>Return <b>null</b>.</li></ol></li></ol></li><li>Append the Record { [[Module]]: <var>module</var>, [[ExportName]]: <var>exportName</var> } to <var>resolveSet</var>.</li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[LocalExportEntries]], do<ol><li>If <var>e</var>.[[ExportName]] is <var>exportName</var>, then<ol><li>Assert: <var>module</var> provides the direct binding for this export.</li><li>Return ResolvedBinding Record { [[Module]]: <var>module</var>, [[BindingName]]: <var>e</var>.[[LocalName]] }.</li></ol></li></ol></li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[IndirectExportEntries]], do<ol><li>If <var>e</var>.[[ExportName]] is <var>exportName</var>, then<ol><li>Assert: <var>e</var>.[[ModuleRequest]] is not <b>null</b>.</li><li>Let <var>importedModule</var> be GetImportedModule(<var>module</var>, <var>e</var>.[[ModuleRequest]]).</li><li>If <var>e</var>.[[ImportName]] is <emu-const>namespace</emu-const>, then<ol><li>Assert: <var>module</var> does not provide the direct binding for this export.</li><li>Return ResolvedBinding Record { [[Module]]: <var>importedModule</var>, [[BindingName]]: <emu-const>namespace</emu-const> }.</li></ol></li><li>Assert: <var>module</var> imports a specific binding for this export.</li><li>Assert: <var>e</var>.[[ImportName]] is a String.</li><li>Return <var>importedModule</var>.ResolveExport(<var>e</var>.[[ImportName]], <var>resolveSet</var>).</li></ol></li></ol></li><li>If <var>exportName</var> is <b>\"default\"</b>, then<ol><li>Assert: A <code>default</code> export was not explicitly defined by this module.</li><li>Return <b>null</b>.</li><li>NOTE: A <code>default</code> export cannot be provided by an <code>export * from \"mod\"</code> declaration.</li></ol></li><li>Let <var>starResolution</var> be <b>null</b>.</li><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[StarExportEntries]], do<ol><li>Assert: <var>e</var>.[[ModuleRequest]] is not <b>null</b>.</li><li>Let <var>importedModule</var> be GetImportedModule(<var>module</var>, <var>e</var>.[[ModuleRequest]]).</li><li>Let <var>resolution</var> be <var>importedModule</var>.ResolveExport(<var>exportName</var>, <var>resolveSet</var>).</li><li>If <var>resolution</var> is <emu-const>ambiguous</emu-const>, return <emu-const>ambiguous</emu-const>.</li><li>If <var>resolution</var> is not <b>null</b>, then<ol><li>Assert: <var>resolution</var> is a ResolvedBinding Record.</li><li>If <var>starResolution</var> is <b>null</b>, then<ol><li>Set <var>starResolution</var> to <var>resolution</var>.</li></ol></li><li>Else,<ol><li>Assert: There is more than one <code>*</code> export that includes the requested name.</li><li>If <var>resolution</var>.[[Module]] and <var>starResolution</var>.[[Module]] are not the same Module Record, return <emu-const>ambiguous</emu-const>.</li><li>If <var>resolution</var>.[[BindingName]] is not <var>starResolution</var>.[[BindingName]], return <emu-const>ambiguous</emu-const>.</li></ol></li></ol></li></ol></li><li>Return <var>starResolution</var>.</li></ol></emu-alg>\n          ","2.1.7.3":"<p>The following are the concrete methods for Source Text Module Record that implement the corresponding Cyclic Module Record abstract methods defined in table-cyclic-module-methods.</p>\n\n          ","2.1.7.3.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>For each ExportEntry Record <var>e</var> of <var>module</var>.[[IndirectExportEntries]], do<ol><li>Assert: <var>e</var>.[[ExportName]] is not <b>null</b>.</li><li>Let <var>resolution</var> be <var>module</var>.ResolveExport(<var>e</var>.[[ExportName]]).</li><li>If <var>resolution</var> is either <b>null</b> or <emu-const>ambiguous</emu-const>, throw a <b>SyntaxError</b> exception.</li><li>Assert: <var>resolution</var> is a ResolvedBinding Record.</li></ol></li><li>Assert: All named exports from <var>module</var> are resolvable.</li><li>Let <var>realm</var> be <var>module</var>.[[Realm]].</li><li>Assert: <var>realm</var> is not <b>undefined</b>.</li><li>Let <var>env</var> be NewModuleEnvironment(<var>realm</var>.[[GlobalEnv]]).</li><li>Set <var>module</var>.[[Environment]] to <var>env</var>.</li><li>For each ImportEntry Record <var>in</var> of <var>module</var>.[[ImportEntries]], do<ol><li>Let <var>importedModule</var> be GetImportedModule(<var>module</var>, <var>in</var>.[[ModuleRequest]]).</li><li>If <var>in</var>.[[ImportName]] is <emu-const>namespace</emu-const>, then<ol><li>Let <var>namespace</var> be GetModuleNamespace(<var>importedModule</var>).</li><li>Perform ! <var>env</var>.CreateImmutableBinding(<var>in</var>.[[LocalName]], <b>true</b>).</li><li>Perform ! <var>env</var>.InitializeBinding(<var>in</var>.[[LocalName]], <var>namespace</var>).</li></ol></li><li>Else,<ol><li>Assert: <var>in</var>.[[ImportName]] is a String.</li><li>Let <var>resolution</var> be <var>importedModule</var>.ResolveExport(<var>in</var>.[[ImportName]]).</li><li>If <var>resolution</var> is either <b>null</b> or <emu-const>ambiguous</emu-const>, throw a <b>SyntaxError</b> exception.</li><li>If <var>resolution</var>.[[BindingName]] is <emu-const>namespace</emu-const>, then<ol><li>Let <var>namespace</var> be GetModuleNamespace(<var>resolution</var>.[[Module]]).</li><li>Perform ! <var>env</var>.CreateImmutableBinding(<var>in</var>.[[LocalName]], <b>true</b>).</li><li>Perform ! <var>env</var>.InitializeBinding(<var>in</var>.[[LocalName]], <var>namespace</var>).</li></ol></li><li>Else,<ol><li>Perform CreateImportBinding(<var>env</var>, <var>in</var>.[[LocalName]], <var>resolution</var>.[[Module]], <var>resolution</var>.[[BindingName]]).</li></ol></li></ol></li></ol></li><li>Let <var>moduleContext</var> be a new ECMAScript code execution context.</li><li>Set the Function of <var>moduleContext</var> to <b>null</b>.</li><li>Assert: <var>module</var>.[[Realm]] is not <b>undefined</b>.</li><li>Set the Realm of <var>moduleContext</var> to <var>module</var>.[[Realm]].</li><li>Set the ScriptOrModule of <var>moduleContext</var> to <var>module</var>.</li><li>Set the VariableEnvironment of <var>moduleContext</var> to <var>module</var>.[[Environment]].</li><li>Set the LexicalEnvironment of <var>moduleContext</var> to <var>module</var>.[[Environment]].</li><li>Set the PrivateEnvironment of <var>moduleContext</var> to <b>null</b>.</li><li>Set <var>module</var>.[[Context]] to <var>moduleContext</var>.</li><li>Push <var>moduleContext</var> onto the execution context stack; <var>moduleContext</var> is now the running execution context.</li><li>Let <var>code</var> be <var>module</var>.[[ECMAScriptCode]].</li><li>Let <var>varDeclarations</var> be the VarScopedDeclarations of <var>code</var>.</li><li>Let <var>declaredVarNames</var> be a new empty List.</li><li>For each element <var>d</var> of <var>varDeclarations</var>, do<ol><li>For each element <var>dn</var> of the BoundNames of <var>d</var>, do<ol><li>If <var>declaredVarNames</var> does not contain <var>dn</var>, then<ol><li>Perform ! <var>env</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>).</li><li>Perform ! <var>env</var>.InitializeBinding(<var>dn</var>, <b>undefined</b>).</li><li>Append <var>dn</var> to <var>declaredVarNames</var>.</li></ol></li></ol></li></ol></li><li>Let <var>lexDeclarations</var> be the LexicallyScopedDeclarations of <var>code</var>.</li><li>Let <var>privateEnv</var> be <b>null</b>.</li><li>For each element <var>d</var> of <var>lexDeclarations</var>, do<ol><li>For each element <var>dn</var> of the BoundNames of <var>d</var>, do<ol><li>If IsConstantDeclaration of <var>d</var> is <b>true</b>, then<ol><li>Perform ! <var>env</var>.CreateImmutableBinding(<var>dn</var>, <b>true</b>).</li></ol></li><li>Else,<ol><li>Perform ! <var>env</var>.CreateMutableBinding(<var>dn</var>, <b>false</b>).</li></ol></li><li>If <var>d</var> is either a <emu-nt>FunctionDeclaration</emu-nt>, a <emu-nt>GeneratorDeclaration</emu-nt>, an <emu-nt>AsyncFunctionDeclaration</emu-nt>, or an <emu-nt>AsyncGeneratorDeclaration</emu-nt>, then<ol><li>Let <var>fo</var> be InstantiateFunctionObject of <var>d</var> with arguments <var>env</var> and <var>privateEnv</var>.</li><li>Perform ! <var>env</var>.InitializeBinding(<var>dn</var>, <var>fo</var>).</li></ol></li></ol></li></ol></li><li>Remove <var>moduleContext</var> from the execution context stack.</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n          ","2.1.7.3.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Source Text Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>Assert: <var>module</var> has been linked and declarations in its module environment have been instantiated.</li><li>Let <var>moduleContext</var> be <var>module</var>.[[Context]].</li><li>If <var>module</var>.[[HasTLA]] is <b>false</b>, then<ol><li>Assert: <var>capability</var> is not present.</li><li>Suspend the running execution context.</li><li>Push <var>moduleContext</var> onto the execution context stack; <var>moduleContext</var> is now the running execution context.</li><li>Let <var>result</var> be Completion(Evaluation of <var>module</var>.[[ECMAScriptCode]]).</li><li>Suspend <var>moduleContext</var> and remove it from the execution context stack.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>If <var>result</var> is an abrupt completion, then<ol><li>Return ? <var>result</var>.</li></ol></li></ol></li><li>Else,<ol><li>Assert: <var>capability</var> is a PromiseCapability Record.</li><li>Perform AsyncBlockStart(<var>capability</var>, <var>module</var>.[[ECMAScriptCode]], <var>moduleContext</var>).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n          ","2.1.8":"<p>A <dfn variants=\"Synthetic Module Records\">Synthetic Module Record</dfn> is used to represent information about a module that is defined by specifications. Its exported names are statically defined at creation, while their corresponding values can change over time using SetSyntheticModuleExport. It has no imports or dependencies.</p>\n\n        <emu-note>A Synthetic Module Record could be used for defining a variety of module types: for example, JSON modules or CSS modules.</emu-note>\n\n        <p>In addition to the fields defined in table-module-record-fields Synthetic Module Records have the additional fields listed in table-synthetic-module-record-fields.</p>\n\n        <emu-table id=\"table-synthetic-module-record-fields\" caption=\"Additional Fields of Synthetic Module Records\">\n          <table>\n            <thead>\n              <tr>\n                <th>Field Name</th>\n                <th>Value Type</th>\n                <th>Meaning</th>\n              </tr>\n            </thead>\n            <tr>\n              <td>[[ExportNames]]</td>\n              <td>a List of Strings</td>\n              <td>The names of the exports of the module. This list does not contain duplicates.</td>\n            </tr>\n            <tr>\n              <td>[[EvaluationSteps]]</td>\n              <td>an Abstract Closure</td>\n              <td>The initialization logic to perform upon evaluation of the module, taking the Synthetic Module Record as its sole argument. It must not modify [[ExportNames]]. It may return an abrupt completion.</td>\n            </tr>\n          </table>\n        </emu-table>\n\n        ","2.1.8.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It creates a Synthetic Module Record whose default export is <var>defaultExport</var>.</dd>\n          </dl>\n          <emu-alg><ol><li>Let <var>realm</var> be the current Realm Record.</li><li>Let <var>setDefaultExport</var> be a new Abstract Closure with parameters (<var>module</var>) that captures <var>defaultExport</var> and performs the following steps when called:<ol><li>Perform SetSyntheticModuleExport(<var>module</var>, <b>\"default\"</b>, <var>defaultExport</var>).</li><li>Return NormalCompletion(<emu-const>unused</emu-const>).</li></ol></li><li>Return the Synthetic Module Record { [[Realm]]: <var>realm</var>, [[Environment]]: <emu-const>empty</emu-const>, [[Namespace]]: <emu-const>empty</emu-const>, [[HostDefined]]: <b>undefined</b>, [[ExportNames]]: « <b>\"default\"</b> », [[EvaluationSteps]]: <var>setDefaultExport</var> }.</li></ol></emu-alg>\n        ","2.1.8.2":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd></dd>\n          </dl>\n\n          <emu-alg><ol><li>Let <var>parseResult</var> be ? ParseJSON(<var>source</var>).</li><li>Return CreateDefaultExportSyntheticModule(<var>parseResult</var>.[[Value]]).</li></ol></emu-alg>\n        ","2.1.8.3":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It can be used to set or change the exported value for an existing export of a Synthetic Module Record.</dd>\n          </dl>\n\n          <emu-alg><ol><li>Assert: <var>module</var>.[[ExportNames]] contains <var>exportName</var>.</li><li>Let <var>envRec</var> be <var>module</var>.[[Environment]].</li><li>Assert: <var>envRec</var> is not <emu-const>empty</emu-const>.</li><li>Perform ! <var>envRec</var>.SetMutableBinding(<var>exportName</var>, <var>exportValue</var>, <b>true</b>).</li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n        ","2.1.8.4":"<p>The following are the concrete methods for Synthetic Module Record that implement the corresponding Module Record abstract methods defined in table-abstract-methods-of-module-records.</p>\n\n          ","2.1.8.4.1":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of LoadRequestedModules does not use <var>hostDefined</var>.</li><li>Return ! PromiseResolve(<code class=\"emu-intrinsic\">%Promise%</code>, <b>undefined</b>).</li></ol></emu-alg>\n\n            <emu-note>\n              Synthetic Module Records have no dependencies.\n            </emu-note>\n          ","2.1.8.4.2":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of GetExportedNames does not use <var>exportStarSet</var>.</li><li>Return <var>module</var>.[[ExportNames]].</li></ol></emu-alg>\n          ","2.1.8.4.3":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>NOTE: This implementation of ResolveExport does not use <var>resolveSet</var>.</li><li>If <var>module</var>.[[ExportNames]] does not contain <var>exportName</var>, return <b>null</b>.</li><li>Return ResolvedBinding Record { [[Module]]: <var>module</var>, [[BindingName]]: <var>exportName</var> }.</li></ol></emu-alg>\n          ","2.1.8.4.4":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>Let <var>realm</var> be <var>module</var>.[[Realm]].</li><li>Let <var>env</var> be NewModuleEnvironment(<var>realm</var>.[[GlobalEnv]]).</li><li>Set <var>module</var>.[[Environment]] to <var>env</var>.</li><li>For each String <var>exportName</var> of <var>module</var>.[[ExportNames]], do<ol><li>Perform ! <var>env</var>.CreateMutableBinding(<var>exportName</var>, <b>false</b>).</li><li>Perform ! <var>env</var>.InitializeBinding(<var>exportName</var>, <b>undefined</b>).</li></ol></li><li>Return NormalCompletion(<emu-const>unused</emu-const>).</li></ol></emu-alg>\n          ","2.1.8.4.5":"<dl class=\"header\">\n              <dt>for</dt>\n              <dd>a Synthetic Module Record <var>module</var></dd>\n            </dl>\n\n            <emu-alg><ol><li>Let <var>moduleContext</var> be a new ECMAScript code execution context.</li><li>Set the Function of <var>moduleContext</var> to <b>null</b>.</li><li>Set the Realm of <var>moduleContext</var> to <var>module</var>.[[Realm]].</li><li>Set the ScriptOrModule of <var>moduleContext</var> to <var>module</var>.</li><li>Set the VariableEnvironment of <var>moduleContext</var> to <var>module</var>.[[Environment]].</li><li>Set the LexicalEnvironment of <var>moduleContext</var> to <var>module</var>.[[Environment]].</li><li>Suspend the running execution context.</li><li>Push <var>moduleContext</var> onto the execution context stack; <var>moduleContext</var> is now the running execution context.</li><li>Let <var>steps</var> be <var>module</var>.[[EvaluationSteps]].</li><li>Let <var>result</var> be Completion(<var>steps</var>(<var>module</var>)).</li><li>Suspend <var>moduleContext</var> and remove it from the execution context stack.</li><li>Resume the context that is now on the top of the execution context stack as the running execution context.</li><li>Let <var>pc</var> be ! NewPromiseCapability(<code class=\"emu-intrinsic\">%Promise%</code>).</li><li>IfAbruptRejectPromise(<var>result</var>, <var>pc</var>).</li><li>Perform ! Call(<var>pc</var>.[[Resolve]], <b>undefined</b>, « <b>undefined</b> »).</li><li>Return <var>pc</var>.[[Promise]].</li></ol></emu-alg>\n          ","2.1.9":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n\n        <emu-alg><ol><li>Let <var>records</var> be a List consisting of each LoadedModuleRequest Record <var>r</var> of <var>referrer</var>.[[LoadedModules]] such that ModuleRequestsEqual(<var>r</var>, <var>request</var>) is <b>true</b>.</li><li>Assert: <var>records</var> has exactly one element, since LoadRequestedModules has completed successfully on <var>referrer</var> prior to invoking this abstract operation.</li><li>Let <var>record</var> be the sole element of <var>records</var>.</li><li>Return <var>record</var>.[[Module]].</li></ol></emu-alg>\n      ","2.1.10":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n\n        <emu-note id=\"note-HostLoadImportedModule-referrer-Realm-Record\">\n          <p>An example of when <var>referrer</var> can be a Realm Record is in a web browser host. There, if a user clicks on a control given by</p>\n\n          <pre><code class=\"html\">&lt;button type=\"button\" onclick=\"import('./foo.mjs')\"&gt;Click me&lt;/button&gt;</code></pre>\n\n          <p>there will be no active script or module at the time the <emu-xref href=\"#sec-import-calls\"><code>import()</code></emu-xref> expression runs. More generally, this can happen in any situation where the host pushes execution contexts with <b>null</b> ScriptOrModule components onto the execution context stack.</p>\n        </emu-note>\n\n        <p>An implementation of HostLoadImportedModule must conform to the following requirements:</p>\n        <ul>\n          <li>\n            The host environment must perform FinishLoadingImportedModule(<var>referrer</var>, <var>moduleRequest</var>, <var>payload</var>, <var>result</var>), where <var>result</var> is either a normal completion containing the loaded Module Record or a throw completion, either synchronously or asynchronously.\n          </li>\n          <li>\n            <p>If this operation is called multiple times with two (<var>referrer</var>, <var>moduleRequest</var>) pairs such that:</p>\n            <ul>\n              <li>the first <var>referrer</var> is the same as the second <var>referrer</var>;</li>\n              <li>ModuleRequestsEqual(the first <var>moduleRequest</var>, the second <var>moduleRequest</var>) is <b>true</b>;</li>\n            </ul>\n            <p>and it performs FinishLoadingImportedModule(<var>referrer</var>, <var>moduleRequest</var>, <var>payload</var>, <var>result</var>) where <var>result</var> is a normal completion, then it must perform FinishLoadingImportedModule(<var>referrer</var>, <var>moduleRequest</var>, <var>payload</var>, <var>result</var>) with the same <var>result</var> each time.</p>\n          </li>\n          <li>\n            <p>If <var>moduleRequest</var>.[[Attributes]] has an entry <var>entry</var> such that <var>entry</var>.[[Key]] is <b>\"type\"</b> and <var>entry</var>.[[Value]] is <b>\"json\"</b>, when the host environment performs FinishLoadingImportedModule(<var>referrer</var>, <var>moduleRequest</var>, <var>payload</var>, <var>result</var>), <var>result</var> must either be the Completion Record returned by an invocation of ParseJSONModule or a throw completion.</p>\n          </li>\n          <li>\n            The operation must treat <var>payload</var> as an opaque value to be passed through to FinishLoadingImportedModule.\n          </li>\n        </ul>\n\n        <p>The actual process performed is host-defined, but typically consists of performing whatever I/O operations are necessary to load the appropriate Module Record. Multiple different (<var>referrer</var>, <var>moduleRequest</var>.[[Specifier]], <var>moduleRequest</var>.[[Attributes]]) triples may map to the same Module Record instance. The actual mapping semantics is host-defined but typically a normalization process is applied to <var>specifier</var> as part of the mapping process. A typical normalization process would include actions such as expansion of relative and abbreviated path specifiers.</p>\n\n        <emu-note>\n          <p>The above text requires that hosts support JSON modules when imported with <code>type: \"json\"</code> (and HostLoadImportedModule completes normally), but it does not prohibit hosts from supporting JSON modules when imported without <code>type: \"json\"</code>.</p>\n        </emu-note>\n      ","2.1.11":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n        <emu-alg><ol><li>If <var>result</var> is a normal completion, then<ol><li>If <var>referrer</var>.[[LoadedModules]] contains a LoadedModuleRequest Record <var>record</var> such that ModuleRequestsEqual(<var>record</var>, <var>moduleRequest</var>) is <b>true</b>, then<ol><li>Assert: <var>record</var>.[[Module]] and <var>result</var>.[[Value]] are the same Module Record.</li></ol></li><li>Else,<ol><li>Append the LoadedModuleRequest Record { [[Specifier]]: <var>moduleRequest</var>.[[Specifier]], [[Attributes]]: <var>moduleRequest</var>.[[Attributes]], [[Module]]: <var>result</var>.[[Value]] } to <var>referrer</var>.[[LoadedModules]].</li></ol></li></ol></li><li>If <var>payload</var> is a GraphLoadingState Record, then<ol><li>Perform ContinueModuleLoading(<var>payload</var>, <var>result</var>).</li></ol></li><li>Else,<ol><li>Perform ContinueDynamicImport(<var>payload</var>, <var>result</var>).</li></ol></li><li>Return <emu-const>unused</emu-const>.</li></ol></emu-alg>\n      ","2.1.12":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd></dd>\n        </dl>\n        <emu-alg><ol><li>Let <var>supported</var> be HostGetSupportedImportAttributes().</li><li>For each ImportAttribute Record <var>attribute</var> of <var>attributes</var>, do<ol><li>If <var>supported</var> does not contain <var>attribute</var>.[[Key]], return <b>false</b>.</li></ol></li><li>Return <b>true</b>.</li></ol></emu-alg>\n\n        ","2.1.12.1":"<dl class=\"header\">\n            <dt>description</dt>\n            <dd>It allows host environments to specify which import attributes they support. Only attributes with supported keys will be provided to the host.</dd>\n          </dl>\n\n          <p>An implementation of HostGetSupportedImportAttributes must conform to the following requirements:</p>\n\n          <ul>\n            <li>It must return a List of Strings, each indicating a supported attribute.</li>\n\n            <li>Each time this operation is called, it must return the same List with the same contents in the same order.</li>\n          </ul>\n\n          <p>The default implementation of HostGetSupportedImportAttributes is to return a new empty List.</p>\n\n          <emu-note>The purpose of requiring the host to specify its supported import attributes, rather than passing all attributes to the host and letting it then choose which ones it wants to handle, is to ensure that unsupported attributes are handled in a consistent way across different hosts.</emu-note>\n        ","2.1.13":"<dl class=\"header\">\n          <dt>description</dt>\n          <dd>It retrieves the Module Namespace Object representing <var>module</var>'s exports, lazily creating it the first time it was requested, and storing it in <var>module</var>.[[Namespace]] for future retrieval.</dd>\n        </dl>\n\n        <emu-alg><ol><li>Assert: If <var>module</var> is a Cyclic Module Record, then <var>module</var>.[[Status]] is not <emu-const>new</emu-const> or <emu-const>unlinked</emu-const>.</li><li>Let <var>namespace</var> be <var>module</var>.[[Namespace]].</li><li>If <var>namespace</var> is <emu-const>empty</emu-const>, then<ol><li>Let <var>exportedNames</var> be <var>module</var>.GetExportedNames().</li><li>Let <var>unambiguousNames</var> be a new empty List.</li><li>For each element <var>name</var> of <var>exportedNames</var>, do<ol><li>Let <var>resolution</var> be <var>module</var>.ResolveExport(<var>name</var>).</li><li>If <var>resolution</var> is a ResolvedBinding Record, append <var>name</var> to <var>unambiguousNames</var>.</li></ol></li><li>Set <var>namespace</var> to ModuleNamespaceCreate(<var>module</var>, <var>unambiguousNames</var>).</li></ol></li><li>Return <var>namespace</var>.</li></ol></emu-alg>\n        <emu-note>\n          <p>GetModuleNamespace never throws. Instead, unresolvable names are simply excluded from the namespace at this point. They will lead to a real linking error later unless they are all ambiguous star exports that are not explicitly requested anywhere.</p>\n        </emu-note>\n      ","2.1.14":"<pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return <b>undefined</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleBody : ModuleItemList</pre>\n        <emu-alg><ol><li>Let <var>result</var> be Completion(Evaluation of <emu-nt>ModuleItemList</emu-nt>).</li><li>If <var>result</var> is a normal completion and <var>result</var>.[[Value]] is <emu-const>empty</emu-const>, then<ol><li>Return <b>undefined</b>.</li></ol></li><li>Return ? <var>result</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>sl</var> be ? Evaluation of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>s</var> be Completion(Evaluation of <emu-nt>ModuleItem</emu-nt>).</li><li>Return ? UpdateEmpty(<var>s</var>, <var>sl</var>).</li></ol></emu-alg>\n        <emu-note>\n          <p>The value of a <emu-nt>ModuleItemList</emu-nt> is the value of the last value-producing item in the <emu-nt>ModuleItemList</emu-nt>.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItem : ImportDeclaration</pre>\n        <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      ","2.2":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ImportDeclaration :\n  `import` ImportClause FromClause WithClause? `;`\n  `import` ModuleSpecifier WithClause? `;`\n\nImportClause :\n  ImportedDefaultBinding\n  NameSpaceImport\n  NamedImports\n  ImportedDefaultBinding `,` NameSpaceImport\n  ImportedDefaultBinding `,` NamedImports\n\nImportedDefaultBinding :\n  ImportedBinding\n\nNameSpaceImport :\n  `*` `as` ImportedBinding\n\nNamedImports :\n  `{` `}`\n  `{` ImportsList `}`\n  `{` ImportsList `,` `}`\n\nFromClause :\n  `from` ModuleSpecifier\n\nImportsList :\n  ImportSpecifier\n  ImportsList `,` ImportSpecifier\n\nImportSpecifier :\n  ImportedBinding\n  ModuleExportName `as` ImportedBinding\n\nModuleSpecifier :\n  StringLiteral\n\nImportedBinding :\n  BindingIdentifier[~Yield, +Await]\n\nWithClause :\n  `with` `{` `}`\n  `with` `{` WithEntries `,`? `}`\n\nWithEntries :\n  AttributeKey `:` StringLiteral\n  AttributeKey `:` StringLiteral `,` WithEntries\n\nAttributeKey :\n  IdentifierName\n  StringLiteral</pre>\n\n      ","2.2.1":"<pre class=\"emu-grammar\">ModuleItem : ImportDeclaration</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the BoundNames of <emu-nt>ImportDeclaration</emu-nt> contains any duplicate entries.\n          </li>\n        </ul>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` WithEntries `,`? `}`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if WithClauseToAttributes of <emu-nt>WithClause</emu-nt> has two different entries <var>a</var> and <var>b</var> such that <var>a</var>.[[Key]] is <var>b</var>.[[Key]].\n          </li>\n        </ul>\n      ","2.2.2":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>entries1</var> be the ImportEntries of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>entries2</var> be the ImportEntries of <emu-nt>ModuleItem</emu-nt>.</li><li>Return the list-concatenation of <var>entries1</var> and <var>entries2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ExportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ImportClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Let <var>module</var> be the sole element of the ModuleRequests of <emu-nt>ImportDeclaration</emu-nt>.</li><li>Return the ImportEntriesForModule of <emu-nt>ImportClause</emu-nt> with argument <var>module</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportDeclaration : `import` ModuleSpecifier WithClause? `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n      ","2.2.3":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">ImportClause : ImportedDefaultBinding `,` NameSpaceImport</pre>\n        <emu-alg><ol><li>Let <var>entries1</var> be the ImportEntriesForModule of <emu-nt>ImportedDefaultBinding</emu-nt> with argument <var>module</var>.</li><li>Let <var>entries2</var> be the ImportEntriesForModule of <emu-nt>NameSpaceImport</emu-nt> with argument <var>module</var>.</li><li>Return the list-concatenation of <var>entries1</var> and <var>entries2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportClause : ImportedDefaultBinding `,` NamedImports</pre>\n        <emu-alg><ol><li>Let <var>entries1</var> be the ImportEntriesForModule of <emu-nt>ImportedDefaultBinding</emu-nt> with argument <var>module</var>.</li><li>Let <var>entries2</var> be the ImportEntriesForModule of <emu-nt>NamedImports</emu-nt> with argument <var>module</var>.</li><li>Return the list-concatenation of <var>entries1</var> and <var>entries2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportedDefaultBinding : ImportedBinding</pre>\n        <emu-alg><ol><li>Let <var>localName</var> be the sole element of the BoundNames of <emu-nt>ImportedBinding</emu-nt>.</li><li>Let <var>defaultEntry</var> be the ImportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <b>\"default\"</b>, [[LocalName]]: <var>localName</var> }.</li><li>Return « <var>defaultEntry</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NameSpaceImport : `*` `as` ImportedBinding</pre>\n        <emu-alg><ol><li>Let <var>localName</var> be the StringValue of <emu-nt>ImportedBinding</emu-nt>.</li><li>Let <var>entry</var> be the ImportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <emu-const>namespace</emu-const>, [[LocalName]]: <var>localName</var> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedImports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportsList : ImportsList `,` ImportSpecifier</pre>\n        <emu-alg><ol><li>Let <var>specs1</var> be the ImportEntriesForModule of <emu-nt>ImportsList</emu-nt> with argument <var>module</var>.</li><li>Let <var>specs2</var> be the ImportEntriesForModule of <emu-nt>ImportSpecifier</emu-nt> with argument <var>module</var>.</li><li>Return the list-concatenation of <var>specs1</var> and <var>specs2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportSpecifier : ImportedBinding</pre>\n        <emu-alg><ol><li>Let <var>localName</var> be the sole element of the BoundNames of <emu-nt>ImportedBinding</emu-nt>.</li><li>Let <var>entry</var> be the ImportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <var>localName</var>, [[LocalName]]: <var>localName</var> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ImportSpecifier : ModuleExportName `as` ImportedBinding</pre>\n        <emu-alg><ol><li>Let <var>importName</var> be the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li><li>Let <var>localName</var> be the StringValue of <emu-nt>ImportedBinding</emu-nt>.</li><li>Let <var>entry</var> be the ImportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <var>importName</var>, [[LocalName]]: <var>localName</var> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n      ","2.2.4":"<dl class=\"header\">\n        </dl>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithClause : `with` `{` WithEntries `,`? `}`</pre>\n        <emu-alg><ol><li>Let <var>attributes</var> be WithClauseToAttributes of <emu-nt>WithEntries</emu-nt>.</li><li>Sort <var>attributes</var> according to the lexicographic order of their [[Key]] field, treating the value of each such field as a sequence of UTF-16 code unit values. NOTE: This sorting is observable only in that hosts are prohibited from changing behaviour based on the order in which attributes are enumerated.</li><li>Return <var>attributes</var>.</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithEntries : AttributeKey `:` StringLiteral</pre>\n        <emu-alg><ol><li>Let <var>key</var> be the PropName of <emu-nt>AttributeKey</emu-nt>.</li><li>Let <var>entry</var> be the ImportAttribute Record { [[Key]]: <var>key</var>, [[Value]]: the SV of <emu-nt>StringLiteral</emu-nt> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n\n        <pre class=\"emu-grammar\">WithEntries : AttributeKey `:` StringLiteral `,` WithEntries</pre>\n        <emu-alg><ol><li>Let <var>key</var> be the PropName of <emu-nt>AttributeKey</emu-nt>.</li><li>Let <var>entry</var> be the ImportAttribute Record { [[Key]]: <var>key</var>, [[Value]]: the SV of <emu-nt>StringLiteral</emu-nt> }.</li><li>Let <var>rest</var> be WithClauseToAttributes of <emu-nt>WithEntries</emu-nt>.</li><li>Return the list-concatenation of « <var>entry</var> » and <var>rest</var>.</li></ol></emu-alg>\n      ","2.3":"<h2>Syntax</h2>\n      <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` ExportFromClause FromClause WithClause? `;`\n  `export` NamedExports `;`\n  `export` VariableStatement[~Yield, +Await]\n  `export` Declaration[~Yield, +Await]\n  `export` `default` HoistableDeclaration[~Yield, +Await, +Default]\n  `export` `default` ClassDeclaration[~Yield, +Await, +Default]\n  `export` `default` [lookahead &notin; { `function`, `async` [no LineTerminator here] `function`, `class` }] AssignmentExpression[+In, ~Yield, +Await] `;`\n\nExportFromClause :\n  `*`\n  `*` `as` ModuleExportName\n  NamedExports\n\nNamedExports :\n  `{` `}`\n  `{` ExportsList `}`\n  `{` ExportsList `,` `}`\n\nExportsList :\n  ExportSpecifier\n  ExportsList `,` ExportSpecifier\n\nExportSpecifier :\n  ModuleExportName\n  ModuleExportName `as` ModuleExportName</pre>\n\n      ","2.3.1":"<pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <ul>\n          <li>\n            It is a Syntax Error if the ReferencedBindings of <emu-nt>NamedExports</emu-nt> contains any <emu-nt>StringLiteral</emu-nt>s.\n          </li>\n          <li>\n            For each <emu-nt>IdentifierName</emu-nt> <var>n</var> in the ReferencedBindings of <emu-nt>NamedExports</emu-nt>: It is a Syntax Error if the StringValue of <var>n</var> is a <emu-nt>ReservedWord</emu-nt> or the StringValue of <var>n</var> is one of <b>\"implements\"</b>, <b>\"interface\"</b>, <b>\"let\"</b>, <b>\"package\"</b>, <b>\"private\"</b>, <b>\"protected\"</b>, <b>\"public\"</b>, or <b>\"static\"</b>.\n          </li>\n        </ul>\n        <emu-note>\n          <p>The above rule means that each ReferencedBindings of <emu-nt>NamedExports</emu-nt> is treated as an <emu-nt>IdentifierReference</emu-nt>.</p>\n        </emu-note>\n      ","2.3.2":"<dl class=\"header\">\n        </dl>\n        <emu-note>\n          <p>ExportedBindings are the locally bound names that are explicitly associated with a <emu-nt>Module</emu-nt>'s ExportedNames.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>names1</var> be the ExportedBindings of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>names2</var> be the ExportedBindings of <emu-nt>ModuleItem</emu-nt>.</li><li>Return the list-concatenation of <var>names1</var> and <var>names2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return the ExportedBindings of <emu-nt>NamedExports</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return the BoundNames of <emu-nt>VariableStatement</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return the BoundNames of <emu-nt>Declaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return the BoundNames of this <emu-nt>ExportDeclaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let <var>names1</var> be the ExportedBindings of <emu-nt>ExportsList</emu-nt>.</li><li>Let <var>names2</var> be the ExportedBindings of <emu-nt>ExportSpecifier</emu-nt>.</li><li>Return the list-concatenation of <var>names1</var> and <var>names2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of the first <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n      ","2.3.3":"<dl class=\"header\">\n        </dl>\n        <emu-note>\n          <p>ExportedNames are the externally visible names that a <emu-nt>Module</emu-nt> explicitly maps to one of its local name bindings.</p>\n        </emu-note>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>names1</var> be the ExportedNames of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>names2</var> be the ExportedNames of <emu-nt>ModuleItem</emu-nt>.</li><li>Return the list-concatenation of <var>names1</var> and <var>names2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem : ExportDeclaration</pre>\n        <emu-alg><ol><li>Return the ExportedNames of <emu-nt>ExportDeclaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Return the ExportedNames of <emu-nt>ExportFromClause</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*` `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : NamedExports</pre>\n        <emu-alg><ol><li>Return the ExportedNames of <emu-nt>NamedExports</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return the BoundNames of <emu-nt>VariableStatement</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return the BoundNames of <emu-nt>Declaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration :\n  `export` `default` HoistableDeclaration\n  `export` `default` ClassDeclaration\n  `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Return « <b>\"default\"</b> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let <var>names1</var> be the ExportedNames of <emu-nt>ExportsList</emu-nt>.</li><li>Let <var>names2</var> be the ExportedNames of <emu-nt>ExportSpecifier</emu-nt>.</li><li>Return the list-concatenation of <var>names1</var> and <var>names2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the StringValue of the second <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n      ","2.3.4":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">Module : [empty]</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItemList : ModuleItemList ModuleItem</pre>\n        <emu-alg><ol><li>Let <var>entries1</var> be the ExportEntries of <emu-nt>ModuleItemList</emu-nt>.</li><li>Let <var>entries2</var> be the ExportEntries of <emu-nt>ModuleItem</emu-nt>.</li><li>Return the list-concatenation of <var>entries1</var> and <var>entries2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleItem :\n  ImportDeclaration\n  StatementListItem</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` ExportFromClause FromClause WithClause? `;`</pre>\n        <emu-alg><ol><li>Let <var>module</var> be the sole element of the ModuleRequests of <emu-nt>ExportDeclaration</emu-nt>.</li><li>Return the ExportEntriesForModule of <emu-nt>ExportFromClause</emu-nt> with argument <var>module</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return the ExportEntriesForModule of <emu-nt>NamedExports</emu-nt> with argument <b>null</b>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Let <var>entries</var> be a new empty List.</li><li>Let <var>names</var> be the BoundNames of <emu-nt>VariableStatement</emu-nt>.</li><li>For each element <var>name</var> of <var>names</var>, do<ol><li>Append the ExportEntry Record { [[ModuleRequest]]: <b>null</b>, [[ImportName]]: <b>null</b>, [[LocalName]]: <var>name</var>, [[ExportName]]: <var>name</var> } to <var>entries</var>.</li></ol></li><li>Return <var>entries</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Let <var>entries</var> be a new empty List.</li><li>Let <var>names</var> be the BoundNames of <emu-nt>Declaration</emu-nt>.</li><li>For each element <var>name</var> of <var>names</var>, do<ol><li>Append the ExportEntry Record { [[ModuleRequest]]: <b>null</b>, [[ImportName]]: <b>null</b>, [[LocalName]]: <var>name</var>, [[ExportName]]: <var>name</var> } to <var>entries</var>.</li></ol></li><li>Return <var>entries</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` HoistableDeclaration</pre>\n        <emu-alg><ol><li>Let <var>names</var> be the BoundNames of <emu-nt>HoistableDeclaration</emu-nt>.</li><li>Let <var>localName</var> be the sole element of <var>names</var>.</li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: <b>null</b>, [[ImportName]]: <b>null</b>, [[LocalName]]: <var>localName</var>, [[ExportName]]: <b>\"default\"</b> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` ClassDeclaration</pre>\n        <emu-alg><ol><li>Let <var>names</var> be the BoundNames of <emu-nt>ClassDeclaration</emu-nt>.</li><li>Let <var>localName</var> be the sole element of <var>names</var>.</li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: <b>null</b>, [[ImportName]]: <b>null</b>, [[LocalName]]: <var>localName</var>, [[ExportName]]: <b>\"default\"</b> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>Let <var>entry</var> be the ExportEntry Record { [[ModuleRequest]]: <b>null</b>, [[ImportName]]: <b>null</b>, [[LocalName]]: <b>\"\\</b>default\\<b>\"</b>, [[ExportName]]: <b>\"default\"</b> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n        <emu-note>\n          <p><b>\"\\</b>default\\<b>\"</b> is used within this specification as a synthetic name for anonymous default export values. See <emu-xref href=\"#note-star-default-star\">this note</emu-xref> for more details.</p>\n        </emu-note>\n      ","2.3.5":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">ExportFromClause : `*`</pre>\n        <emu-alg><ol><li>Let <var>entry</var> be the ExportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <emu-const>all-but-default</emu-const>, [[LocalName]]: <b>null</b>, [[ExportName]]: <b>null</b> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportFromClause : `*` `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Let <var>exportName</var> be the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li><li>Let <var>entry</var> be the ExportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <emu-const>namespace</emu-const>, [[LocalName]]: <b>null</b>, [[ExportName]]: <var>exportName</var> }.</li><li>Return « <var>entry</var> ».</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let <var>specs1</var> be the ExportEntriesForModule of <emu-nt>ExportsList</emu-nt> with argument <var>module</var>.</li><li>Let <var>specs2</var> be the ExportEntriesForModule of <emu-nt>ExportSpecifier</emu-nt> with argument <var>module</var>.</li><li>Return the list-concatenation of <var>specs1</var> and <var>specs2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName</pre>\n        <emu-alg><ol><li>Let <var>sourceName</var> be the StringValue of <emu-nt>ModuleExportName</emu-nt>.</li><li>If <var>module</var> is <b>null</b>, then<ol><li>Let <var>localName</var> be <var>sourceName</var>.</li><li>Let <var>importName</var> be <b>null</b>.</li></ol></li><li>Else,<ol><li>Let <var>localName</var> be <b>null</b>.</li><li>Let <var>importName</var> be <var>sourceName</var>.</li></ol></li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <var>importName</var>, [[LocalName]]: <var>localName</var>, [[ExportName]]: <var>sourceName</var> }.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Let <var>sourceName</var> be the StringValue of the first <emu-nt>ModuleExportName</emu-nt>.</li><li>Let <var>exportName</var> be the StringValue of the second <emu-nt>ModuleExportName</emu-nt>.</li><li>If <var>module</var> is <b>null</b>, then<ol><li>Let <var>localName</var> be <var>sourceName</var>.</li><li>Let <var>importName</var> be <b>null</b>.</li></ol></li><li>Else,<ol><li>Let <var>localName</var> be <b>null</b>.</li><li>Let <var>importName</var> be <var>sourceName</var>.</li></ol></li><li>Return a List whose sole element is a new ExportEntry Record { [[ModuleRequest]]: <var>module</var>, [[ImportName]]: <var>importName</var>, [[LocalName]]: <var>localName</var>, [[ExportName]]: <var>exportName</var> }.</li></ol></emu-alg>\n      ","2.3.6":"<dl class=\"header\">\n        </dl>\n        <pre class=\"emu-grammar\">NamedExports : `{` `}`</pre>\n        <emu-alg><ol><li>Return a new empty List.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportsList : ExportsList `,` ExportSpecifier</pre>\n        <emu-alg><ol><li>Let <var>names1</var> be the ReferencedBindings of <emu-nt>ExportsList</emu-nt>.</li><li>Let <var>names2</var> be the ReferencedBindings of <emu-nt>ExportSpecifier</emu-nt>.</li><li>Return the list-concatenation of <var>names1</var> and <var>names2</var>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportSpecifier : ModuleExportName `as` ModuleExportName</pre>\n        <emu-alg><ol><li>Return the ReferencedBindings of the first <emu-nt>ModuleExportName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleExportName : IdentifierName</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the <emu-nt>IdentifierName</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ModuleExportName : StringLiteral</pre>\n        <emu-alg><ol><li>Return a List whose sole element is the <emu-nt>StringLiteral</emu-nt>.</li></ol></emu-alg>\n      ","2.3.7":"<pre class=\"emu-grammar\">ExportDeclaration :\n  `export` ExportFromClause FromClause WithClause? `;`\n  `export` NamedExports `;`</pre>\n        <emu-alg><ol><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` VariableStatement</pre>\n        <emu-alg><ol><li>Return ? Evaluation of <emu-nt>VariableStatement</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` Declaration</pre>\n        <emu-alg><ol><li>Return ? Evaluation of <emu-nt>Declaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` HoistableDeclaration</pre>\n        <emu-alg><ol><li>Return ? Evaluation of <emu-nt>HoistableDeclaration</emu-nt>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` ClassDeclaration</pre>\n        <emu-alg><ol><li>Let <var>value</var> be ? BindingClassDeclarationEvaluation of <emu-nt>ClassDeclaration</emu-nt>.</li><li>Let <var>className</var> be the sole element of the BoundNames of <emu-nt>ClassDeclaration</emu-nt>.</li><li>If <var>className</var> is <b>\"\\</b>default\\<b>\"</b>, then<ol><li>Let <var>env</var> be the running execution context's LexicalEnvironment.</li><li>Perform ? InitializeBoundName(<b>\"\\</b>default\\<b>\"</b>, <var>value</var>, <var>env</var>).</li></ol></li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n        <pre class=\"emu-grammar\">ExportDeclaration : `export` `default` AssignmentExpression `;`</pre>\n        <emu-alg><ol><li>If IsAnonymousFunctionDefinition(<emu-nt>AssignmentExpression</emu-nt>) is <b>true</b>, then<ol><li>Let <var>value</var> be ? NamedEvaluation of <emu-nt>AssignmentExpression</emu-nt> with argument <b>\"default\"</b>.</li></ol></li><li>Else,<ol><li>Let <var>rhs</var> be ? Evaluation of <emu-nt>AssignmentExpression</emu-nt>.</li><li>Let <var>value</var> be ? GetValue(<var>rhs</var>).</li></ol></li><li>Let <var>env</var> be the running execution context's LexicalEnvironment.</li><li>Perform ? InitializeBoundName(<b>\"\\</b>default\\<b>\"</b>, <var>value</var>, <var>env</var>).</li><li>Return <emu-const>empty</emu-const>.</li></ol></emu-alg>\n      "};
export function Sec({ id }) {
  const html = sections[id] ?? '';
  return <div className="ecma-spec" dangerouslySetInnerHTML={{ __html: html }} />;
}
